/*
 * elf_writer.c — Native ELF relocatable object writer for b1cc (M15)
 *
 * Strategy:
 *   1. Parse the GNU AS text produced by backend_arm64/x86_64/i386 into
 *      a simple section/symbol/reloc model.
 *   2. Encode x86_64 or i386 instructions to binary with a minimal table-
 *      driven encoder covering the exact instruction set emitted by b1cc.
 *   3. Lay out ELF64 (x86_64) or ELF32 (i386) sections and write bytes.
 *
 * The assembly text is well-structured because it is machine-generated by
 * b1cc, not hand-written.  That makes parsing straightforward.
 */

#include "elf_writer.h"
#include "diagnostics.h"
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <ctype.h>

/* =========================================================================
 * ELF constants
 * ========================================================================= */

/* ELF identification */
#define ELF_MAG0  0x7f
#define ELF_MAG1  'E'
#define ELF_MAG2  'L'
#define ELF_MAG3  'F'
#define ELFCLASS32   1
#define ELFCLASS64   2
#define ELFDATA2LSB  1       /* little-endian */
#define ET_REL       1       /* relocatable object */
#define EM_386      3
#define EM_X86_64  62
#define EV_CURRENT  1
#define ELFOSABI_NONE 0

/* Section header types */
#define SHT_NULL      0
#define SHT_PROGBITS  1
#define SHT_SYMTAB    2
#define SHT_STRTAB    3
#define SHT_RELA      4
#define SHT_NOBITS    8
#define SHT_REL       9

/* Section header flags */
#define SHF_WRITE      0x1
#define SHF_ALLOC      0x2
#define SHF_EXECINSTR  0x4

/* Symbol binding / type */
#define STB_LOCAL   0
#define STB_GLOBAL  1
#define STT_NOTYPE  0
#define STT_OBJECT  1
#define STT_FUNC    2
#define STT_SECTION 3
#define STT_FILE    4
#define STV_DEFAULT 0

/* Special section indices */
#define SHN_UNDEF  0
#define SHN_ABS    0xfff1
#define SHN_COMMON 0xfff2

/* Relocation types — x86_64 */
#define R_X86_64_NONE    0
#define R_X86_64_32      1
#define R_X86_64_PC32    2
#define R_X86_64_GOTPCREL 9
#define R_X86_64_PLT32   4
#define R_X86_64_32S     11

/* Relocation types — i386 */
#define R_386_NONE   0
#define R_386_32     1
#define R_386_PC32   2
#define R_386_GOT32  3
#define R_386_PLT32  4

/* =========================================================================
 * Byte buffer (growable byte array)
 * ========================================================================= */

typedef struct {
    uint8_t *data;
    size_t   size;
    size_t   cap;
} ByteBuf;

static void bb_init(ByteBuf *b) {
    b->data = NULL;
    b->size = 0;
    b->cap  = 0;
}

static void bb_reserve(ByteBuf *b, size_t extra) {
    size_t need = b->size + extra;
    if (need > b->cap) {
        size_t newcap = (b->cap == 0) ? 256 : b->cap * 2;
        while (newcap < need) newcap *= 2;
        b->data = realloc(b->data, newcap);
        if (!b->data) diagnostics_fatal("elf_writer: out of memory");
        b->cap = newcap;
    }
}

static void bb_write8(ByteBuf *b, uint8_t v) {
    bb_reserve(b, 1);
    b->data[b->size++] = v;
}

static void bb_write16le(ByteBuf *b, uint16_t v) {
    bb_reserve(b, 2);
    b->data[b->size++] = (uint8_t)(v);
    b->data[b->size++] = (uint8_t)(v >> 8);
}

static void bb_write32le(ByteBuf *b, uint32_t v) {
    bb_reserve(b, 4);
    b->data[b->size++] = (uint8_t)(v);
    b->data[b->size++] = (uint8_t)(v >> 8);
    b->data[b->size++] = (uint8_t)(v >> 16);
    b->data[b->size++] = (uint8_t)(v >> 24);
}

static void bb_write64le(ByteBuf *b, uint64_t v) {
    bb_write32le(b, (uint32_t)(v));
    bb_write32le(b, (uint32_t)(v >> 32));
}

static void bb_writebytes(ByteBuf *b, const uint8_t *src, size_t n) {
    bb_reserve(b, n);
    memcpy(b->data + b->size, src, n);
    b->size += n;
}

/* Patch a 32-bit LE value at offset */
static void bb_patch32le(ByteBuf *b, size_t off, uint32_t v) {
    b->data[off+0] = (uint8_t)(v);
    b->data[off+1] = (uint8_t)(v >> 8);
    b->data[off+2] = (uint8_t)(v >> 16);
    b->data[off+3] = (uint8_t)(v >> 24);
}

static void bb_free(ByteBuf *b) {
    free(b->data);
    b->data = NULL;
    b->size = b->cap = 0;
}

/* Align buffer to `align` bytes by inserting zero padding */
static void bb_align(ByteBuf *b, size_t align) {
    if (align <= 1) return;
    while (b->size % align) bb_write8(b, 0);
}

static void elf_write_shdr64(ByteBuf *out, uint32_t name, uint32_t type,
                             uint64_t flags, uint64_t addr, uint64_t offset,
                             uint64_t size, uint32_t link, uint32_t info,
                             uint64_t addralign, uint64_t entsize) {
    bb_write32le(out, name);
    bb_write32le(out, type);
    bb_write64le(out, flags);
    bb_write64le(out, addr);
    bb_write64le(out, offset);
    bb_write64le(out, size);
    bb_write32le(out, link);
    bb_write32le(out, info);
    bb_write64le(out, addralign);
    bb_write64le(out, entsize);
}

static void elf_write_shdr32(ByteBuf *out, uint32_t name, uint32_t type,
                             uint32_t flags, uint32_t addr, uint32_t offset,
                             uint32_t size, uint32_t link, uint32_t info,
                             uint32_t addralign, uint32_t entsize) {
    bb_write32le(out, name);
    bb_write32le(out, type);
    bb_write32le(out, flags);
    bb_write32le(out, addr);
    bb_write32le(out, offset);
    bb_write32le(out, size);
    bb_write32le(out, link);
    bb_write32le(out, info);
    bb_write32le(out, addralign);
    bb_write32le(out, entsize);
}

/* =========================================================================
 * String table builder
 * ========================================================================= */

typedef struct {
    ByteBuf buf;
} Strtab;

static void strtab_init(Strtab *st) {
    bb_init(&st->buf);
    bb_write8(&st->buf, 0); /* index 0 = empty string */
}

static uint32_t strtab_add(Strtab *st, const char *s) {
    uint32_t off = (uint32_t)st->buf.size;
    size_t n = strlen(s) + 1;
    bb_reserve(&st->buf, n);
    memcpy(st->buf.data + st->buf.size, s, n);
    st->buf.size += n;
    return off;
}

static void strtab_free(Strtab *st) { bb_free(&st->buf); }

/* =========================================================================
 * Symbol and relocation model
 * ========================================================================= */

typedef struct {
    char     name[256];
    uint32_t name_off;   /* index into .strtab */
    uint32_t shndx;      /* section index or SHN_UNDEF */
    uint64_t value;      /* offset within section */
    uint32_t size;
    uint8_t  bind;       /* STB_LOCAL / STB_GLOBAL */
    uint8_t  type;       /* STT_FUNC / STT_OBJECT / etc. */
    int      defined;    /* 1 if defined in this TU */
} ElfSym;

typedef struct {
    char     sym_name[256]; /* symbol name to look up */
    uint64_t offset;        /* offset in .text where the 4-byte field is */
    int32_t  addend;        /* addend (for RELA; for REL encoded inline) */
    uint32_t type;          /* R_X86_64_PLT32 / R_386_PC32 etc. */
} ElfReloc;

/* Dynamic arrays */
typedef struct { ElfSym *data; int count; int cap; } SymArr;
typedef struct { ElfReloc *data; int count; int cap; } RelocArr;

static void symarr_push(SymArr *a, const ElfSym *s) {
    if (a->count == a->cap) {
        a->cap = a->cap ? a->cap * 2 : 16;
        a->data = realloc(a->data, sizeof(ElfSym) * a->cap);
    }
    a->data[a->count++] = *s;
}

static void relocarr_push(RelocArr *a, const ElfReloc *r) {
    if (a->count == a->cap) {
        a->cap = a->cap ? a->cap * 2 : 16;
        a->data = realloc(a->data, sizeof(ElfReloc) * a->cap);
    }
    a->data[a->count++] = *r;
}

/* =========================================================================
 * Simple text-line parser helpers
 * ========================================================================= */

/* Skip whitespace (not newlines) */
static const char *skip_ws(const char *p) {
    while (*p == ' ' || *p == '\t') p++;
    return p;
}

/* Parse a signed 64-bit integer literal (decimal, hex with 0x) */
static int64_t parse_int(const char *s) {
    if (s[0] == '0' && (s[1] == 'x' || s[1] == 'X'))
        return (int64_t)strtoull(s + 2, NULL, 16);
    return strtoll(s, NULL, 10);
}

/* =========================================================================
 * x86_64 instruction encoder
 *
 * Covers exactly the instructions emitted by backend_x86_64.c:
 *
 *   pushq %reg64 / popq %reg64
 *   movq  src, dst   (reg64→reg64, imm64→reg64, mem→reg64, reg64→mem)
 *   movl  (for gstore 32-bit)
 *   movw  / movb     (byte/word gstore)
 *   addq  / subq     imm/reg
 *   imulq %rcx, %rax
 *   cqto
 *   idivq %rcx
 *   andq / orq / xorq / notq / negq
 *   shlq / sarq / shrq  %cl, %rax
 *   cmpq  imm/reg, %rax
 *   sete/setne/setl/setg/setle/setge/setb/seta/setbe/setae  %al
 *   movzbq %al, %rax
 *   movsbq / movswq / movslq  (sign extension)
 *   movsbl / movswq / movslq  (RIP-relative & indexed)
 *   leaq  sym(%rip), %rax   (RIP-relative LEA → relocation)
 *   call  sym / call *%r11
 *   xorl  %eax, %eax
 *   je / jmp  label
 *   leave / ret
 *   shrq / sarq $imm, %rax
 *   andq $imm, %rax
 *   movq (%rdi), %rcx  etc.
 *   movq %rcx, (%rdi)  etc.
 *
 * This encoder uses a line-at-a-time approach: strip the leading spaces,
 * match the mnemonic, then parse operands.
 *
 * Register numbering (ModRM/REX):
 *   rax=0 rcx=1 rdx=2 rbx=3 rsp=4 rbp=5 rsi=6 rdi=7
 *   r8=8  r9=9  r10=10 r11=11 r12=12 r13=13 r14=14 r15=15
 *
 * ========================================================================= */

typedef struct {
    const char *name;
    int         num;   /* low 3 bits = reg field; bit 3 = REX.R/B extension */
} RegEntry;

static const RegEntry x64_regs[] = {
    /* 64-bit GPR */
    {"%rax",0},{"%rcx",1},{"%rdx",2},{"%rbx",3},
    {"%rsp",4},{"%rbp",5},{"%rsi",6},{"%rdi",7},
    {"%r8",8},{"%r9",9},{"%r10",10},{"%r11",11},
    {"%r12",12},{"%r13",13},{"%r14",14},{"%r15",15},
    /* 32-bit */
    {"%eax",0},{"%ecx",1},{"%edx",2},{"%ebx",3},
    {"%esp",4},{"%ebp",5},{"%esi",6},{"%edi",7},
    {"%r8d",8},{"%r9d",9},{"%r10d",10},{"%r11d",11},
    /* 16-bit */
    {"%ax",0},{"%cx",1},{"%dx",2},{"%bx",3},
    {"%r11w",11},
    /* 8-bit */
    {"%al",0},{"%cl",1},{"%dl",2},{"%bl",3},
    {"%r11b",11},
    {NULL,0}
};

static int x64_reg_num(const char *name) {
    for (int i = 0; x64_regs[i].name; i++) {
        if (strcmp(x64_regs[i].name, name) == 0)
            return x64_regs[i].num;
    }
    return -1;
}

/* REX prefix: W=1 (64-bit), R=reg ext, X=0, B=rm/base ext */
static uint8_t rex(int W, int R, int B) {
    return (uint8_t)(0x40 | (W ? 0x08 : 0) | ((R & 8) ? 0x04 : 0) | ((B & 8) ? 0x01 : 0));
}

/* ModRM byte: mod=3 (register), reg=r, rm=m */
static uint8_t modrm_rr(int r, int m) {
    return (uint8_t)(0xC0 | ((r & 7) << 3) | (m & 7));
}

/* ModRM byte: mod=0 (disp0/rip-relative), reg, rm */
static uint8_t modrm_r0(int r, int m) {
    return (uint8_t)(0x00 | ((r & 7) << 3) | (m & 7));
}

/* ModRM byte: mod=1 (disp8), reg, rm */
static uint8_t modrm_r8(int r, int m) {
    return (uint8_t)(0x40 | ((r & 7) << 3) | (m & 7));
}

/* ModRM byte: mod=2 (disp32), reg, rm */
static uint8_t modrm_r32(int r, int m) {
    return (uint8_t)(0x80 | ((r & 7) << 3) | (m & 7));
}

/* SIB byte */
static uint8_t sib_byte(int scale_log2, int idx, int base) {
    return (uint8_t)((scale_log2 << 6) | ((idx & 7) << 3) | (base & 7));
}

/* Encode `op reg, (base,idx,scale)` (an MR/RM instruction with a SIB byte).
 * `w` selects REX.W (64-bit). `reg` is the register operand (dest for a load
 * opcode like 0x8B, source for a store opcode like 0x89). Handles extended
 * registers (r8–r15) and the base==rbp/r13 case (which forces a disp8). */
static void enc_mem_idx(ByteBuf *text, uint8_t op, int w, int reg, int base, int idx, int scale) {
    int scale_log2 = (scale == 2) ? 1 : (scale == 4) ? 2 : (scale == 8) ? 3 : 0;
    if (w || reg >= 8 || base >= 8 || idx >= 8)
        bb_write8(text, (uint8_t)(0x40 | (w ? 8 : 0) | ((reg >= 8) ? 4 : 0) | ((idx >= 8) ? 2 : 0) | ((base >= 8) ? 1 : 0)));
    bb_write8(text, op);
    int use_disp8 = ((base & 7) == 5); /* mod=00 + base=rbp/r13 means no-base; use disp8=0 */
    bb_write8(text, (uint8_t)((use_disp8 ? 0x40 : 0x00) | ((reg & 7) << 3) | 0x04));
    bb_write8(text, sib_byte(scale_log2, idx, base));
    if (use_disp8) bb_write8(text, 0);
}

/*
 * Operand types for the encoder
 */
typedef enum {
    OT_REG64,   /* %rax, %r11, etc. */
    OT_REG32,   /* %eax, %r11d, etc. */
    OT_REG16,   /* %ax, %r11w */
    OT_REG8,    /* %al, %cl, %r11b */
    OT_IMM,     /* $42 */
    OT_MEM_RIP, /* sym(%rip) */
    OT_MEM_BASE,/* N(%rbp) / N(%rsp) etc. */
    OT_MEM_IDX, /* (%rax,%rcx,8) */
    OT_MEM_INDIR, /* (%rdi) - no offset */
    OT_LABEL,   /* local label like .L0 */
    OT_SYM,     /* external symbol */
    OT_NONE,
} OpType;

typedef struct {
    OpType   type;
    int      reg;       /* register number (0-15) */
    int64_t  imm;       /* immediate / displacement */
    char     sym[256];  /* symbol name (MEM_RIP, LABEL, SYM) */
    int      base;      /* base register for MEM_BASE / MEM_IDX */
    int      idx;       /* index register for MEM_IDX */
    int      scale;     /* scale (1,2,4,8) for MEM_IDX */
    int      is64;      /* 1 for 64-bit register */
    int      is_gotpcrel; /* 1 for @GOTPCREL(%rip) addressing */
} Operand;

/* Determine operand size class from register name */
static OpType reg_optype(const char *s) {
    if (s[1] == 'r') return OT_REG64;          /* %rax, %r8.. */
    if (s[1] == 'e') return OT_REG32;
    /* 8-bit low byte regs (%al %cl %dl %bl) end in 'l' — MUST be tested before
     * the 16-bit case below, which would otherwise claim them (they are 3 chars
     * ending in the alpha 'l'), misclassifying %cl and silently dropping every
     * variable shift `shl %cl, ...` and byte move through %al/%dl. */
    if (strlen(s) == 3 && s[2] == 'l') return OT_REG8; /* %al %cl %dl %bl */
    if (strlen(s) == 3 && isalpha((unsigned char)s[2])) {
        /* %ax, %bx .. */
        return OT_REG16;
    }
    if (strlen(s) == 4 && (s[3] == 'b' || s[3] == 'w')) return OT_REG8;
    return OT_REG64; /* fallback */
}

/* Infer the AT&T size suffix ('q'/'l'/'w'/'b') for a suffixless GP mnemonic from
 * its operands. GNU inline asm (and hand-written asm) commonly omit the suffix,
 * letting the assembler derive the size from a register operand — e.g. the M22
 * asm template `mov %2, %0` becomes `mov %rax, %r8`. We pick the width of the
 * LAST direct (non-addressing) register operand, which in AT&T order is the
 * destination and never the shift-count %cl, so `shl %cl, %rax` sizes as 'q'.
 * Registers inside parentheses are addressing operands (always 64-bit) and do
 * not determine the operation size, so they are skipped. Defaults to 'q'. */
static char infer_gp_suffix(const char *ops) {
    char suf = 'q';
    int seen = 0;
    for (const char *q = ops; *q; q++) {
        if (*q != '%') continue;
        const char *b = q;
        while (b > ops && (b[-1] == ' ' || b[-1] == '\t')) b--;
        if (b > ops && b[-1] == '(') continue; /* base/index reg — skip */
        switch (reg_optype(q)) {
            case OT_REG64: suf = 'q'; seen = 1; break;
            case OT_REG32: suf = 'l'; seen = 1; break;
            case OT_REG16: suf = 'w'; seen = 1; break;
            case OT_REG8:  suf = 'b'; seen = 1; break;
            default: break;
        }
    }
    (void)seen;
    return suf;
}

/* Is `m` a suffixless GP mnemonic whose size we can derive from its operands?
 * These are the two-operand ALU/move ops that inline asm emits without a suffix;
 * suffixed forms (movq/addl/…) don't match and keep their existing handling. */
static int is_suffixless_gp(const char *m) {
    static const char *ops[] = {
        "mov", "add", "sub", "and", "or", "xor", "cmp", "test",
        "adc", "sbb", "shl", "shr", "sar", "sal", "imul", "xchg", "lea",
    };
    for (size_t i = 0; i < sizeof(ops) / sizeof(ops[0]); i++)
        if (strcmp(m, ops[i]) == 0) return 1;
    return 0;
}

/*
 * Parse one operand from `p`, advance *p past it.
 * Returns OT_NONE on failure.
 */
static Operand parse_operand_x64(const char **pp) {
    Operand op = {0};
    op.type = OT_NONE;
    const char *p = skip_ws(*pp);

    if (*p == '$') {
        /* Immediate */
        p++;
        op.type = OT_IMM;
        char buf[64];
        int i = 0;
        if (*p == '-') { buf[i++] = '-'; p++; }
        while (*p && *p != ',' && *p != '\n' && *p != ' ' && i < 63)
            buf[i++] = *p++;
        buf[i] = 0;
        op.imm = parse_int(buf);
        *pp = p;
        return op;
    }

    if (*p == '%') {
        /* Register */
        char reg[16];
        int n = 0;
        while (*p && *p != ',' && *p != ')' && *p != '\n' && *p != ' ' && n < 15)
            reg[n++] = *p++;
        reg[n] = 0;
        op.type = reg_optype(reg);
        op.reg  = x64_reg_num(reg);
        op.is64 = (op.type == OT_REG64);
        *pp = p;
        return op;
    }

    if (*p == '(') {
        /* (%base) or (%base,%idx,scale) */
        p++;
        char base[16]; int nb = 0;
        while (*p && *p != ',' && *p != ')' && nb < 15) base[nb++] = *p++;
        base[nb] = 0;
        op.base = x64_reg_num(base);
        if (*p == ',') {
            p++; /* skip , */
            char idx[16]; int ni = 0;
            while (*p && *p != ',' && *p != ')' && ni < 15) idx[ni++] = *p++;
            idx[ni] = 0;
            op.idx = x64_reg_num(idx);
            if (*p == ',') {
                p++; /* skip , */
                op.scale = (int)strtol(p, (char **)&p, 10);
            }
        }
        if (*p == ')') p++;
        if (op.idx != 0 || op.scale != 0) {
            op.type = OT_MEM_IDX;
        } else {
            op.type = OT_MEM_INDIR;
        }
        op.imm = 0;
        *pp = p;
        return op;
    }

    /* Check for N(%reg) or sym(%rip) */
    {
        char sym[256]; int ns = 0;
        int is_num = 0;
        int64_t disp = 0;
        const char *q = p;

        /* Try to read displacement or symbol */
        if (*q == '-' || isdigit((unsigned char)*q)) {
            /* numeric displacement */
            is_num = 1;
            char tbuf[32]; int ti = 0;
            if (*q == '-') tbuf[ti++] = *q++;
            while (isdigit((unsigned char)*q) && ti < 31) tbuf[ti++] = *q++;
            tbuf[ti] = 0;
            disp = strtoll(tbuf, NULL, 10);
        } else if (*q && *q != '\n') {
            /* symbol */
            while (*q && *q != '(' && *q != '\n' && ns < 255) sym[ns++] = *q++;
            sym[ns] = 0;
            /* Check for @GOTPCREL suffix (PIC mode) */
            const char *got_suffix = strstr(sym, "@GOTPCREL");
            if (got_suffix) {
                ns = (int)(got_suffix - sym);
                sym[ns] = 0;
                op.is_gotpcrel = 1;
            }
        }

        if (*q == '(') {
            q++;
            char base[16]; int nb = 0;
            while (*q && *q != ')' && *q != ',' && nb < 15) base[nb++] = *q++;
            base[nb] = 0;
            int breg = x64_reg_num(base);
            if (*q == ',') {
                /* indexed: sym(%base,%idx,scale) — not expected in b1cc output */
                while (*q && *q != ')') q++;
            }
            if (*q == ')') q++;
            if (strcmp(base, "%rip") == 0) {
                op.type = OT_MEM_RIP;
                if (is_num) {
                    snprintf(sym, sizeof(sym), "%lld", (long long)disp);
                }
                strncpy(op.sym, sym, 255);
            } else {
                op.type = OT_MEM_BASE;
                op.base = breg;
                op.imm  = disp;
            }
            *pp = q;
            return op;
        } else if (!is_num && ns > 0) {
            /* bare symbol */
            strncpy(op.sym, sym, 255);
            op.type = OT_SYM;
            *pp = q;
            return op;
        }
    }

    *pp = p;
    return op; /* OT_NONE */
}

/* Encode a 64-bit REX+opcode+ModRM for reg-to-reg instruction */
static void enc_rr64(ByteBuf *out, uint8_t op, int dst, int src) {
    bb_write8(out, rex(1, src, dst));
    bb_write8(out, op);
    bb_write8(out, modrm_rr(src, dst));
}

/* Encode REX.W + opcode + ModRM for mem[base+disp] -> reg or reg -> mem */
static void enc_mem_base(ByteBuf *out, uint8_t op, int reg, int base, int32_t disp, int W) {
    uint8_t r = rex(W, reg, base);
    if (r != 0x40 || (reg & 8) || (base & 8)) bb_write8(out, r);
    else if (W) bb_write8(out, 0x48); /* REX.W always needed for 64-bit */
    bb_write8(out, op);
    int rb = base & 7;
    int rg = reg & 7;
    if (disp == 0 && rb != 5 /* rbp */) {
        bb_write8(out, modrm_r0(rg, rb));
        if (rb == 4 /* rsp */) bb_write8(out, 0x24); /* SIB: rsp base, no index */
    } else if (disp >= -128 && disp <= 127) {
        bb_write8(out, modrm_r8(rg, rb));
        if (rb == 4) bb_write8(out, 0x24);
        bb_write8(out, (uint8_t)(int8_t)disp);
    } else {
        bb_write8(out, modrm_r32(rg, rb));
        if (rb == 4) bb_write8(out, 0x24);
        bb_write32le(out, (uint32_t)(int32_t)disp);
    }
}

/* =========================================================================
 * x86_64 assembly encoder (one instruction line at a time)
 *
 * Returns 1 if encoded, 0 if line is a directive/label/blank/comment.
 * On unknown instruction: calls diagnostics_fatal().
 * ========================================================================= */

/* Context passed through encoding of a single function */
typedef struct {
    /* Label → offset map (for local jumps) */
    char   **label_names;
    int32_t *label_offsets;
    int      label_count;
    int      label_cap;
    /* Pending forward-jump patches */
    struct { size_t patch_off; char label[64]; } *patches;
    int  patch_count;
    int  patch_cap;
} EncCtx;

static void ctx_init(EncCtx *ctx) {
    ctx->label_names   = NULL;
    ctx->label_offsets = NULL;
    ctx->label_count   = ctx->label_cap = 0;
    ctx->patches       = NULL;
    ctx->patch_count   = ctx->patch_cap = 0;
}

static void ctx_free(EncCtx *ctx) {
    for (int i = 0; i < ctx->label_count; i++) free(ctx->label_names[i]);
    free(ctx->label_names);
    free(ctx->label_offsets);
    free(ctx->patches);
}

static void ctx_add_label(EncCtx *ctx, const char *name, int32_t off) {
    if (ctx->label_count == ctx->label_cap) {
        ctx->label_cap = ctx->label_cap ? ctx->label_cap * 2 : 8;
        ctx->label_names   = realloc(ctx->label_names,   sizeof(char *)   * ctx->label_cap);
        ctx->label_offsets = realloc(ctx->label_offsets, sizeof(int32_t)  * ctx->label_cap);
    }
    ctx->label_names  [ctx->label_count] = strdup(name);
    ctx->label_offsets[ctx->label_count] = off;
    ctx->label_count++;
}

static int32_t ctx_find_label(EncCtx *ctx, const char *name) {
    for (int i = 0; i < ctx->label_count; i++)
        if (strcmp(ctx->label_names[i], name) == 0)
            return ctx->label_offsets[i];
    return -1;
}

static void ctx_add_patch(EncCtx *ctx, size_t patch_off, const char *label) {
    if (ctx->patch_count == ctx->patch_cap) {
        ctx->patch_cap = ctx->patch_cap ? ctx->patch_cap * 2 : 8;
        ctx->patches = realloc(ctx->patches, sizeof(ctx->patches[0]) * ctx->patch_cap);
    }
    ctx->patches[ctx->patch_count].patch_off = patch_off;
    strncpy(ctx->patches[ctx->patch_count].label, label, 63);
    ctx->patch_count++;
}

/*
 * Encode one x86_64 instruction line into `text`.
 * `sym_offset` is the current offset of the start of this function in .text.
 * Relocations are appended to `relocs` with offset relative to start of .text.
 *
 * Returns 1 if an instruction was emitted, 0 if line was skipped (directive/blank).
 */
static int x64_encode_line(const char *line, ByteBuf *text, EncCtx *ctx,
                            size_t fn_start, RelocArr *relocs) {
    const char *p = skip_ws(line);
    if (!*p || *p == '\n' || *p == '#') return 0;
    if (*p == '.') return 0;  /* assembler directive */

    /* Check for label definition (ends with ':') */
    {
        const char *q = p;
        char lname[256]; int ln = 0;
        while (*q && *q != ':' && *q != ' ' && *q != '\n' && ln < 255)
            lname[ln++] = *q++;
        lname[ln] = 0;
        if (*q == ':') {
            /* It's a label */
            ctx_add_label(ctx, lname, (int32_t)(text->size - fn_start));
            /* Patch any pending forward jumps to this label */
            for (int i = 0; i < ctx->patch_count; i++) {
                if (strcmp(ctx->patches[i].label, lname) == 0) {
                    size_t off = ctx->patches[i].patch_off;
                    int32_t target = (int32_t)(text->size - fn_start);
                    int32_t disp   = target - (int32_t)(off - fn_start + 4);
                    bb_patch32le(text, off, (uint32_t)disp);
                }
            }
            return 0;
        }
    }

    /* Parse mnemonic */
    char mnem[32]; int mn = 0;
    while (*p && *p != ' ' && *p != '\t' && *p != '\n' && mn < 31)
        mnem[mn++] = *p++;
    mnem[mn] = 0;

    p = skip_ws(p);

    /* Normalize suffixless GP mnemonics (inline-asm style, e.g. `mov %rax, %r8`)
     * to their sized form so the size-specific handlers below encode them
     * instead of falling through to the nop catch-all. */
    if (is_suffixless_gp(mnem)) {
        size_t mlen = strlen(mnem);
        if (mlen < sizeof(mnem) - 1) {
            mnem[mlen] = infer_gp_suffix(p);
            mnem[mlen + 1] = 0;
        }
    }

    /* ---- pushq ---- */
    if (strcmp(mnem, "pushq") == 0) {
        Operand op = parse_operand_x64(&p);
        if (op.type == OT_REG64) {
            if (op.reg >= 8) { bb_write8(text, rex(0,0,op.reg)); }
            bb_write8(text, 0x50 | (op.reg & 7));
        } else if (op.type == OT_IMM) {
            if (op.imm >= -128 && op.imm <= 127) {
                bb_write8(text, 0x6A);
                bb_write8(text, (uint8_t)(int8_t)op.imm);
            } else {
                bb_write8(text, 0x68);
                bb_write32le(text, (uint32_t)(int32_t)op.imm);
            }
        }
        return 1;
    }

    /* ---- popq ---- */
    if (strcmp(mnem, "popq") == 0) {
        Operand op = parse_operand_x64(&p);
        if (op.type == OT_REG64) {
            if (op.reg >= 8) bb_write8(text, rex(0,0,op.reg));
            bb_write8(text, 0x58 | (op.reg & 7));
        }
        return 1;
    }

    /* ---- ret ---- */
    if (strcmp(mnem, "ret") == 0) {
        bb_write8(text, 0xC3);
        return 1;
    }

    /* ---- leave ---- */
    if (strcmp(mnem, "leave") == 0) {
        bb_write8(text, 0xC9);
        return 1;
    }

    /* ---- nop ---- */
    if (strcmp(mnem, "nop") == 0) {
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- cqto (cqo) ---- */
    if (strcmp(mnem, "cqto") == 0 || strcmp(mnem, "cqo") == 0) {
        bb_write8(text, 0x48); /* REX.W */
        bb_write8(text, 0x99); /* CQO */
        return 1;
    }

    /* ---- xorl %eax, %eax ---- */
    if (strcmp(mnem, "xorl") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        /* 32-bit XOR reg, reg — no REX needed unless extended regs */
        int s = src.reg, d = dst.reg;
        uint8_t pfx = (uint8_t)(0x40 | ((s & 8) ? 0x04 : 0) | ((d & 8) ? 0x01 : 0));
        if (pfx != 0x40) bb_write8(text, pfx);
        bb_write8(text, 0x31);
        bb_write8(text, modrm_rr(s, d));
        return 1;
    }

    /* ---- movq ---- (64-bit move — most common) */
    if (strcmp(mnem, "movq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);

        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            if (imm >= -2147483648LL && imm <= 4294967295LL && imm >= 0) {
                /* MOV r32, imm32 — zero-extends to 64 */
                if (d >= 8) bb_write8(text, rex(0, 0, d));
                bb_write8(text, (uint8_t)(0xB8 | (d & 7)));
                bb_write32le(text, (uint32_t)imm);
            } else if (imm >= -2147483648LL && imm <= 2147483647LL) {
                /* MOV r/m64, sign-extended imm32 (REX.W + C7 /0) */
                bb_write8(text, rex(1, 0, d));
                bb_write8(text, 0xC7);
                bb_write8(text, modrm_rr(0, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            } else {
                /* MOV r64, imm64 (REX.W + B8+r) */
                bb_write8(text, rex(1, 0, d));
                bb_write8(text, (uint8_t)(0xB8 | (d & 7)));
                bb_write64le(text, (uint64_t)imm);
            }
            return 1;
        }

        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            enc_rr64(text, 0x89, dst.reg, src.reg);
            return 1;
        }

        if (src.type == OT_REG64 && dst.type == OT_MEM_BASE) {
            /* MOV [base+disp], reg */
            enc_mem_base(text, 0x89, src.reg, dst.base, (int32_t)dst.imm, 1);
            return 1;
        }

        if (src.type == OT_MEM_BASE && dst.type == OT_REG64) {
            /* MOV reg, [base+disp] */
            enc_mem_base(text, 0x8B, dst.reg, src.base, (int32_t)src.imm, 1);
            return 1;
        }

        if (src.type == OT_REG64 && dst.type == OT_MEM_INDIR) {
            /* MOV [base], reg */
            enc_mem_base(text, 0x89, src.reg, dst.base, 0, 1);
            return 1;
        }

        if (src.type == OT_MEM_INDIR && dst.type == OT_REG64) {
            enc_mem_base(text, 0x8B, dst.reg, src.base, 0, 1);
            return 1;
        }

        if (src.type == OT_MEM_RIP && dst.type == OT_REG64) {
            /* MOV rax, sym(%rip) — RIP-relative, needs relocation */
            int d = dst.reg;
            bb_write8(text, rex(1, d, 0));
            bb_write8(text, 0x8B);
            bb_write8(text, modrm_r0(d, 5)); /* mod=00, rm=101 = RIP-relative */
            /* Relocation: R_X86_64_PC32 or R_X86_64_GOTPCREL at current offset, addend=-4 */
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0); /* placeholder */
            return 1;
        }

        /* movq %reg, N(%rsp) — same as MEM_BASE */
        if (src.type == OT_REG64 && (dst.type == OT_MEM_BASE)) {
            enc_mem_base(text, 0x89, src.reg, dst.base, (int32_t)dst.imm, 1);
            return 1;
        }

        /* movq %reg, (%base,%idx,scale) and the load direction — array/word indexing */
        if (src.type == OT_REG64 && dst.type == OT_MEM_IDX) {
            enc_mem_idx(text, 0x89, 1, src.reg, dst.base, dst.idx, dst.scale);
            return 1;
        }
        if (src.type == OT_MEM_IDX && dst.type == OT_REG64) {
            enc_mem_idx(text, 0x8B, 1, dst.reg, src.base, src.idx, src.scale);
            return 1;
        }

        /* Fallthrough: unexpected operand combo — emit nop and warn */
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- movl (32-bit) ---- */
    if (strcmp(mnem, "movl") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);

        if (src.type == OT_REG32 && dst.type == OT_MEM_BASE) {
            enc_mem_base(text, 0x89, src.reg, dst.base, (int32_t)dst.imm, 0);
            return 1;
        }
        if (src.type == OT_MEM_BASE && dst.type == OT_REG32) {
            enc_mem_base(text, 0x8B, dst.reg, src.base, (int32_t)src.imm, 0);
            return 1;
        }
        if (src.type == OT_REG32 && dst.type == OT_MEM_INDIR) {
            enc_mem_base(text, 0x89, src.reg, dst.base, 0, 0);
            return 1;
        }
        /* movl %eax, sym(%rip) or sym@GOTPCREL(%rip) */
        if (src.type == OT_REG32 && dst.type == OT_MEM_RIP) {
            int s = src.reg;
            if (s >= 8) bb_write8(text, rex(0,s,0));
            bb_write8(text, 0x89);
            bb_write8(text, modrm_r0(s, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, dst.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = dst.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        /* movl %reg, (%base,%idx,scale) and the load direction — array indexing */
        if (src.type == OT_REG32 && dst.type == OT_MEM_IDX) {
            enc_mem_idx(text, 0x89, 0, src.reg, dst.base, dst.idx, dst.scale);
            return 1;
        }
        if (src.type == OT_MEM_IDX && dst.type == OT_REG32) {
            enc_mem_idx(text, 0x8B, 0, dst.reg, src.base, src.idx, src.scale);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- movb (8-bit) ---- */
    if (strcmp(mnem, "movb") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        (void)src; (void)dst;
        /* Simplified: emit inline with REX if needed */
        /* movb %al, sym(%rip) or sym@GOTPCREL(%rip) */
        if (src.type == OT_REG8 && dst.type == OT_MEM_RIP) {
            if (src.reg >= 4) bb_write8(text, rex(0, src.reg, 0));
            bb_write8(text, 0x88);
            bb_write8(text, modrm_r0(src.reg, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, dst.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = dst.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        if (src.type == OT_REG8 && dst.type == OT_MEM_BASE) {
            if (src.reg >= 4) bb_write8(text, rex(0, src.reg, dst.base));
            bb_write8(text, 0x88);
            /* simplified: mod=2 disp32 */
            bb_write8(text, (uint8_t)(0x80 | ((src.reg & 7) << 3) | (dst.base & 7)));
            if ((dst.base & 7) == 4) bb_write8(text, 0x24);
            bb_write32le(text, (uint32_t)(int32_t)dst.imm);
            return 1;
        }
        if (src.type == OT_MEM_IDX && dst.type == OT_REG8) {
            /* movb (%rax,%rcx,1), %dl */
            enc_mem_idx(text, 0x8A, 0, dst.reg, src.base, src.idx, src.scale);
            return 1;
        }
        if (src.type == OT_REG8 && dst.type == OT_MEM_IDX) {
            /* movb %dl, (%rax,%rcx,1) */
            enc_mem_idx(text, 0x88, 0, src.reg, dst.base, dst.idx, dst.scale);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- movw (16-bit) ---- */
    if (strcmp(mnem, "movw") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_REG16 && dst.type == OT_MEM_RIP) {
            bb_write8(text, 0x66); /* operand size prefix */
            bb_write8(text, 0x89);
            bb_write8(text, modrm_r0(src.reg & 7, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, dst.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = dst.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        (void)src; (void)dst;
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- addq ---- */
    if (strcmp(mnem, "addq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            if (imm >= -128 && imm <= 127) {
                bb_write8(text, 0x83);
                bb_write8(text, modrm_rr(0, d)); /* /0 = ADD */
                bb_write8(text, (uint8_t)(int8_t)imm);
            } else {
                bb_write8(text, 0x81);
                bb_write8(text, modrm_rr(0, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            }
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            enc_rr64(text, 0x01, dst.reg, src.reg);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- subq ---- */
    if (strcmp(mnem, "subq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            if (imm >= -128 && imm <= 127) {
                bb_write8(text, 0x83);
                bb_write8(text, modrm_rr(5, d)); /* /5 = SUB */
                bb_write8(text, (uint8_t)(int8_t)imm);
            } else {
                bb_write8(text, 0x81);
                bb_write8(text, modrm_rr(5, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            }
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            enc_rr64(text, 0x29, dst.reg, src.reg);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- imulq ---- */
    if (strcmp(mnem, "imulq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, d, d));
            if (imm >= -128 && imm <= 127) {
                bb_write8(text, 0x6B);
                bb_write8(text, modrm_rr(d, d));
                bb_write8(text, (uint8_t)(int8_t)imm);
            } else {
                bb_write8(text, 0x69);
                bb_write8(text, modrm_rr(d, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            }
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            /* IMUL r64, r/m64 = REX.W 0F AF /r */
            bb_write8(text, rex(1, dst.reg, src.reg));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xAF);
            bb_write8(text, modrm_rr(dst.reg, src.reg));
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- idivq ---- */
    if (strcmp(mnem, "idivq") == 0) {
        Operand op = parse_operand_x64(&p);
        bb_write8(text, rex(1, 0, op.reg));
        bb_write8(text, 0xF7);
        bb_write8(text, modrm_rr(7, op.reg)); /* /7 = IDIV */
        return 1;
    }

    /* ---- andq / orq / xorq ---- */
    if (strcmp(mnem, "andq") == 0 || strcmp(mnem, "orq") == 0 || strcmp(mnem, "xorq") == 0) {
        int slash = (strcmp(mnem, "andq") == 0) ? 4 :
                    (strcmp(mnem, "orq")  == 0) ? 1 : 6;
        uint8_t op_rr = (strcmp(mnem, "andq") == 0) ? 0x21 :
                        (strcmp(mnem, "orq")  == 0) ? 0x09 : 0x31;
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            if (imm >= -128 && imm <= 127) {
                bb_write8(text, 0x83);
                bb_write8(text, modrm_rr(slash, d));
                bb_write8(text, (uint8_t)(int8_t)imm);
            } else {
                bb_write8(text, 0x81);
                bb_write8(text, modrm_rr(slash, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            }
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_MEM_INDIR) {
            /* andq/orq %reg, (%base) */
            bb_write8(text, rex(1, src.reg, dst.base));
            bb_write8(text, op_rr);
            bb_write8(text, modrm_r0(src.reg & 7, dst.base & 7));
            if ((dst.base & 7) == 4) bb_write8(text, 0x24);
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            enc_rr64(text, op_rr, dst.reg, src.reg);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- notq / negq ---- */
    if (strcmp(mnem, "notq") == 0 || strcmp(mnem, "negq") == 0) {
        int slash = (strcmp(mnem, "notq") == 0) ? 2 : 3;
        Operand op = parse_operand_x64(&p);
        bb_write8(text, rex(1, 0, op.reg));
        bb_write8(text, 0xF7);
        bb_write8(text, modrm_rr(slash, op.reg));
        return 1;
    }

    /* ---- shlq / sarq / shrq ---- */
    if (strcmp(mnem, "shlq") == 0 || strcmp(mnem, "sarq") == 0 || strcmp(mnem, "shrq") == 0) {
        int slash = (strcmp(mnem, "shlq") == 0) ? 4 :
                    (strcmp(mnem, "sarq") == 0) ? 7 : 5;
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM) {
            int8_t imm = (int8_t)src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            if (imm == 1) {
                bb_write8(text, 0xD1);
                bb_write8(text, modrm_rr(slash, d));
            } else {
                bb_write8(text, 0xC1);
                bb_write8(text, modrm_rr(slash, d));
                bb_write8(text, (uint8_t)imm);
            }
        } else if (src.type == OT_REG8 /* %cl */) {
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            bb_write8(text, 0xD3);
            bb_write8(text, modrm_rr(slash, d));
        }
        return 1;
    }

    /* ---- cmpq ---- */
    if (strcmp(mnem, "cmpq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_IMM && dst.type == OT_REG64) {
            int64_t imm = src.imm;
            int d = dst.reg;
            bb_write8(text, rex(1, 0, d));
            if (imm >= -128 && imm <= 127) {
                bb_write8(text, 0x83);
                bb_write8(text, modrm_rr(7, d)); /* /7 = CMP */
                bb_write8(text, (uint8_t)(int8_t)imm);
            } else {
                bb_write8(text, 0x81);
                bb_write8(text, modrm_rr(7, d));
                bb_write32le(text, (uint32_t)(int32_t)imm);
            }
            return 1;
        }
        if (src.type == OT_REG64 && dst.type == OT_REG64) {
            /* AT&T `cmpq %src,%dst` computes dst-src. enc_rr64 emits the MR form
             * (r/m=dst, reg=src), so use CMP r/m64,r64 (0x39 → r/m-reg = dst-src),
             * NOT 0x3B (RM form, reg-r/m = src-dst) which swaps the comparison. */
            enc_rr64(text, 0x39, dst.reg, src.reg);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- setcc ---- */
    if (strncmp(mnem, "set", 3) == 0) {
        uint8_t op2;
        if      (strcmp(mnem+3, "e")   == 0) op2 = 0x94;
        else if (strcmp(mnem+3, "ne")  == 0) op2 = 0x95;
        else if (strcmp(mnem+3, "l")   == 0) op2 = 0x9C;
        else if (strcmp(mnem+3, "g")   == 0) op2 = 0x9F;
        else if (strcmp(mnem+3, "le")  == 0) op2 = 0x9E;
        else if (strcmp(mnem+3, "ge")  == 0) op2 = 0x9D;
        else if (strcmp(mnem+3, "b")   == 0) op2 = 0x92;
        else if (strcmp(mnem+3, "a")   == 0) op2 = 0x97;
        else if (strcmp(mnem+3, "be")  == 0) op2 = 0x96;
        else                                  op2 = 0x93; /* ae */
        Operand op = parse_operand_x64(&p);
        /* REX needed for %spl, %bpl, %sil, %dil but b1cc only uses %al */
        if (op.reg >= 4 && op.reg <= 7) bb_write8(text, 0x40); /* REX */
        else if (op.reg >= 8) bb_write8(text, rex(0, 0, op.reg));
        bb_write8(text, 0x0F);
        bb_write8(text, op2);
        bb_write8(text, modrm_rr(0, op.reg));
        return 1;
    }

    /* ---- movzbq %al, %rax ---- (zero-extend byte to 64-bit) */
    if (strcmp(mnem, "movzbq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        bb_write8(text, rex(1, dst.reg, src.reg));
        bb_write8(text, 0x0F);
        bb_write8(text, 0xB6); /* MOVZX r64, r/m8 */
        bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }

    /* ---- movsbq %al, %rax ---- (sign-extend byte to 64-bit) */
    if (strcmp(mnem, "movsbq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        /* Check for mem[base+off], dst — OT_MEM_INDIR is (%base) with imm==0, so
         * it shares the OT_MEM_BASE encoding (the imm==0 path below). Without
         * this, `movsbq (%rax), %rax` (a byte load through a pointer) fell to the
         * register-form fallthrough and was mis-encoded as `movsbq %al, %rax`. */
        if (src.type == OT_MEM_BASE || src.type == OT_MEM_INDIR) {
            bb_write8(text, rex(1, dst.reg, src.base));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xBE); /* MOVSX r64, r/m8 */
            int rb = src.base & 7, rg = dst.reg & 7;
            if (src.imm == 0 && rb != 5) {
                bb_write8(text, modrm_r0(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
            } else if (src.imm >= -128 && src.imm <= 127) {
                bb_write8(text, modrm_r8(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
                bb_write8(text, (uint8_t)(int8_t)src.imm);
            } else {
                bb_write8(text, modrm_r32(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
                bb_write32le(text, (uint32_t)(int32_t)src.imm);
            }
            return 1;
        }
        if (src.type == OT_MEM_RIP) {
            bb_write8(text, rex(1, dst.reg, 0));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xBE);
            bb_write8(text, modrm_r0(dst.reg & 7, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        bb_write8(text, rex(1, dst.reg, src.reg));
        bb_write8(text, 0x0F);
        bb_write8(text, 0xBE);
        bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }

    /* ---- movswq (sign-extend word) ---- */
    if (strcmp(mnem, "movswq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_MEM_RIP) {
            bb_write8(text, rex(1, dst.reg, 0));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xBF);
            bb_write8(text, modrm_r0(dst.reg & 7, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        /* movswq (%base[+off]), dst — word load through a pointer (mirrors the
         * movsbq memory form; OT_MEM_INDIR is base with imm==0). */
        if (src.type == OT_MEM_BASE || src.type == OT_MEM_INDIR) {
            bb_write8(text, rex(1, dst.reg, src.base));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xBF); /* MOVSX r64, r/m16 */
            int rb = src.base & 7, rg = dst.reg & 7;
            if (src.imm == 0 && rb != 5) {
                bb_write8(text, modrm_r0(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
            } else if (src.imm >= -128 && src.imm <= 127) {
                bb_write8(text, modrm_r8(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
                bb_write8(text, (uint8_t)(int8_t)src.imm);
            } else {
                bb_write8(text, modrm_r32(rg, rb));
                if (rb == 4) bb_write8(text, 0x24);
                bb_write32le(text, (uint32_t)(int32_t)src.imm);
            }
            return 1;
        }
        bb_write8(text, rex(1, dst.reg, src.reg));
        bb_write8(text, 0x0F);
        bb_write8(text, 0xBF); /* MOVSX r64, r/m16 */
        bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }

    /* ---- movslq (sign-extend dword) ---- */
    if (strcmp(mnem, "movslq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_MEM_RIP) {
            bb_write8(text, rex(1, dst.reg, 0));
            bb_write8(text, 0x63);
            bb_write8(text, modrm_r0(dst.reg & 7, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        /* movslq (%base,%idx,scale), %r64 — sign-extend a dword array element */
        if (src.type == OT_MEM_IDX) {
            enc_mem_idx(text, 0x63, 1, dst.reg, src.base, src.idx, src.scale);
            return 1;
        }
        if (src.type == OT_MEM_INDIR) {
            enc_mem_base(text, 0x63, dst.reg, src.base, 0, 1);
            return 1;
        }
        if (src.type == OT_MEM_BASE) {
            enc_mem_base(text, 0x63, dst.reg, src.base, (int32_t)src.imm, 1);
            return 1;
        }
        bb_write8(text, rex(1, dst.reg, src.reg));
        bb_write8(text, 0x63); /* MOVSXD r64, r/m32 */
        bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }

    /* ---- movsbl (sign-extend byte to 32-bit) ---- */
    if (strcmp(mnem, "movsbl") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_MEM_RIP) {
            /* No REX.W needed for 32-bit */
            if (dst.reg >= 8) bb_write8(text, rex(0, dst.reg, 0));
            bb_write8(text, 0x0F);
            bb_write8(text, 0xBE);
            bb_write8(text, modrm_r0(dst.reg & 7, 5));
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        if (dst.reg >= 8) bb_write8(text, rex(0, dst.reg, src.reg));
        bb_write8(text, 0x0F);
        bb_write8(text, 0xBE);
        bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }

    /* ---- movsbq indexed: movsbq (%rax,%rcx,1), %rax ---- */
    if (strcmp(mnem, "movsbq") == 0 || strcmp(mnem, "movswq") == 0 || strcmp(mnem, "movslq") == 0) {
        /* Already handled above for most cases; this catches indexed forms */
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- leaq sym(%rip) / sym@GOTPCREL(%rip), %rax ---- */
    if (strcmp(mnem, "leaq") == 0) {
        Operand src = parse_operand_x64(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_x64(&p);
        if (src.type == OT_MEM_RIP) {
            int d = dst.reg;
            bb_write8(text, rex(1, d, 0));
            bb_write8(text, 0x8D); /* LEA */
            bb_write8(text, modrm_r0(d & 7, 5)); /* RIP-relative */
            ElfReloc rel = {0};
            strncpy(rel.sym_name, src.sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = src.is_gotpcrel ? R_X86_64_GOTPCREL : R_X86_64_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
            return 1;
        }
        if (src.type == OT_MEM_BASE) {
            int d = dst.reg;
            enc_mem_base(text, 0x8D, d, src.base, (int32_t)src.imm, 1);
            return 1;
        }
        bb_write8(text, 0x90);
        return 1;
    }

    /* ---- call sym / call *%r11 ---- */
    if (strcmp(mnem, "call") == 0) {
        if (*p == '*') {
            /* indirect call: call *%r11 */
            p++;
            Operand op = parse_operand_x64(&p);
            if (op.reg >= 8) bb_write8(text, rex(0, 0, op.reg));
            bb_write8(text, 0xFF);
            bb_write8(text, modrm_rr(2, op.reg)); /* /2 = CALL r/m64 */
        } else {
            /* direct call: call sym */
            char sym[256]; int ns = 0;
            while (*p && *p != '\n' && *p != ' ' && ns < 255) sym[ns++] = *p++;
            sym[ns] = 0;
            bb_write8(text, 0xE8); /* CALL rel32 */
            ElfReloc rel = {0};
            strncpy(rel.sym_name, sym, 255);
            rel.offset = text->size;
            rel.addend = -4;
            rel.type   = R_X86_64_PLT32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0); /* placeholder */
        }
        return 1;
    }

    /* ---- je / jmp (local labels only in b1cc output) ---- */
    if (strcmp(mnem, "je") == 0 || strcmp(mnem, "jmp") == 0) {
        char label[64]; int nl = 0;
        while (*p && *p != '\n' && *p != ' ' && nl < 63) label[nl++] = *p++;
        label[nl] = 0;
        uint8_t opcode = (strcmp(mnem, "je") == 0) ? 0x0F : 0;
        uint8_t opcode2 = (strcmp(mnem, "je") == 0) ? 0x84 : 0xE9;

        int32_t target_off = ctx_find_label(ctx, label);
        if (target_off >= 0) {
            /* Known label: backward jump */
            if (strcmp(mnem, "je") == 0) bb_write8(text, 0x0F);
            bb_write8(text, opcode2);
            int32_t here = (int32_t)(text->size - fn_start + 4);
            bb_write32le(text, (uint32_t)(target_off - here));
        } else {
            /* Forward jump: emit placeholder, record patch */
            if (opcode) bb_write8(text, opcode);
            bb_write8(text, opcode2);
            ctx_add_patch(ctx, text->size, label);
            bb_write32le(text, 0);
        }
        (void)opcode;
        return 1;
    }

    /* ---- movq (%rax,%rcx,N), %rax ---- indexed load */
    if (strcmp(mnem, "movq") == 0) {
        /* Already handled most movq cases; this is a catch-all fallback */
        bb_write8(text, 0x90);
        return 1;
    }

    /* Unknown: emit nop to keep offsets consistent */
    bb_write8(text, 0x90);
    return 1;
}

/* =========================================================================
 * Assembly text parser: split into sections, collect symbols + instructions
 * ========================================================================= */

typedef enum {
    SEC_NONE = 0,
    SEC_TEXT,
    SEC_DATA,
    SEC_RODATA,
    SEC_BSS,
} SectionId;

typedef struct {
    int id;
    char path[256];
} FileEntry;

typedef struct {
    int file_id;
    int line;
    int col;
    size_t offset;
} LocEntry;

typedef struct {
    ByteBuf  text;
    ByteBuf  data;
    ByteBuf  rodata;
    size_t   bss_size;

    SymArr   syms;
    RelocArr text_relocs;
    RelocArr data_relocs;

    FileEntry *files;
    int file_count;
    int file_cap;

    LocEntry *locs;
    int loc_count;
    int loc_cap;
} AsmModel;

static void asm_model_init(AsmModel *m) {
    bb_init(&m->text);
    bb_init(&m->data);
    bb_init(&m->rodata);
    m->bss_size = 0;
    m->syms.data = NULL; m->syms.count = m->syms.cap = 0;
    m->text_relocs.data = NULL; m->text_relocs.count = m->text_relocs.cap = 0;
    m->data_relocs.data = NULL; m->data_relocs.count = m->data_relocs.cap = 0;
    m->files = NULL; m->file_count = m->file_cap = 0;
    m->locs = NULL; m->loc_count = m->loc_cap = 0;
}

static void asm_model_free(AsmModel *m) {
    bb_free(&m->text);
    bb_free(&m->data);
    bb_free(&m->rodata);
    free(m->syms.data);
    free(m->text_relocs.data);
    free(m->data_relocs.data);
    free(m->files);
    free(m->locs);
}

/*
 * parse_asm_x64() — parse GNU AS text (x86_64 target) into AsmModel
 */
static void parse_asm_x64(const char *asm_text, const char *src_path, AsmModel *m) {
    (void)src_path;

    SectionId cur_sec = SEC_NONE;
    const char *p = asm_text;

    /* Current function context for label/jump resolution */
    EncCtx ctx; ctx_init(&ctx);
    size_t fn_start = 0;
    int in_function = 0;

    /* Track pending .globl declarations */
    char pending_globl[256] = "";
    char pending_type_func[256] = ""; /* last .type X, @function */

    while (*p) {
        /* Get current line */
        const char *line_start = p;
        const char *line_end   = p;
        while (*line_end && *line_end != '\n') line_end++;

        /* Make a NUL-terminated copy */
        char line[1024];
        int linelen = (int)(line_end - line_start);
        if (linelen > 1023) linelen = 1023;
        memcpy(line, line_start, linelen);
        line[linelen] = 0;

        /* Advance p */
        p = (*line_end == '\n') ? line_end + 1 : line_end;

        const char *lp = skip_ws(line);

        /* Blank / comment */
        if (!*lp || *lp == '#') continue;

        /* Section switches */
        if (strcmp(lp, ".text") == 0) { cur_sec = SEC_TEXT; continue; }
        if (strcmp(lp, ".data") == 0) { cur_sec = SEC_DATA; continue; }
        if (strcmp(lp, ".section .rodata") == 0 ||
            strcmp(lp, ".rodata") == 0 ||
            strncmp(lp, ".section\t.rodata", 16) == 0 ||
            strncmp(lp, ".section .rodata", 16) == 0) {
            cur_sec = SEC_RODATA; continue;
        }
        if (strcmp(lp, ".bss") == 0) { cur_sec = SEC_BSS; continue; }

        /* .globl declaration */
        if (strncmp(lp, ".globl ", 7) == 0 || strncmp(lp, ".global ", 8) == 0) {
            const char *s = lp + (lp[6] == ' ' ? 7 : 8);
            s = skip_ws(s);
            strncpy(pending_globl, s, 255);
            continue;
        }

        /* .type name, @function */
        if (strncmp(lp, ".type ", 6) == 0) {
            const char *s = skip_ws(lp + 6);
            char tname[256]; int tn = 0;
            while (*s && *s != ',' && tn < 255) tname[tn++] = *s++;
            tname[tn] = 0;
            if (strstr(s, "@function")) {
                strncpy(pending_type_func, tname, 255);
            }
            continue;
        }

        if (*lp == '.') {
            const char *q = lp;
            char lname[256]; int ln = 0;
            while (*q && *q != ':' && *q != ' ' && *q != '\t' && ln < 255) lname[ln++] = *q++;
            lname[ln] = 0;
            if (*q == ':') {
                if (in_function && cur_sec == SEC_TEXT) {
                    ctx_add_label(&ctx, lname, (int32_t)(m->text.size - fn_start));
                    for (int i = 0; i < ctx.patch_count; i++) {
                        if (strcmp(ctx.patches[i].label, lname) == 0) {
                            size_t off = ctx.patches[i].patch_off;
                            int32_t target = (int32_t)(m->text.size - fn_start);
                            int32_t disp   = target - (int32_t)(off - fn_start + 4);
                            bb_patch32le(&m->text, off, (uint32_t)disp);
                        }
                    }
                } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                    ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                    ElfSym sym = {0};
                    strncpy(sym.name, lname, 255);
                    sym.shndx   = (cur_sec == SEC_DATA) ? 3 : 4;
                    sym.value   = (uint64_t)sec_buf->size;
                    sym.size    = 0;
                    sym.bind    = (strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                    sym.type    = STT_OBJECT;
                    sym.defined = 1;
                    symarr_push(&m->syms, &sym);
                }
                continue;
            }
        }

        /* .size .p2align .file .loc .asciz .byte .short .long .quad .zero — directives */
        if (*lp == '.') {
            if (strncmp(lp, ".file ", 6) == 0) {
                const char *s = skip_ws(lp + 6);
                int id = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                char path[256] = "";
                if (*s == '"') {
                    s++;
                    int pi = 0;
                    while (*s && *s != '"' && pi < 255) {
                        path[pi++] = *s++;
                    }
                    path[pi] = 0;
                }
                if (m->file_count == m->file_cap) {
                    m->file_cap = m->file_cap ? m->file_cap * 2 : 4;
                    m->files = realloc(m->files, sizeof(FileEntry) * m->file_cap);
                }
                m->files[m->file_count].id = id;
                strncpy(m->files[m->file_count].path, path, 255);
                m->file_count++;
            } else if (strncmp(lp, ".loc ", 5) == 0) {
                const char *s = skip_ws(lp + 5);
                int file_id = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                int line = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                int col = (int)strtol(s, (char**)&s, 10);
                if (cur_sec == SEC_TEXT) {
                    if (m->loc_count == m->loc_cap) {
                        m->loc_cap = m->loc_cap ? m->loc_cap * 2 : 32;
                        m->locs = realloc(m->locs, sizeof(LocEntry) * m->loc_cap);
                    }
                    m->locs[m->loc_count].file_id = file_id;
                    m->locs[m->loc_count].line = line;
                    m->locs[m->loc_count].col = col;
                    m->locs[m->loc_count].offset = m->text.size;
                    m->loc_count++;
                }
            } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                if (strncmp(lp, ".byte ", 6) == 0) {
                    int64_t v = parse_int(skip_ws(lp + 6));
                    bb_write8(sec_buf, (uint8_t)(v & 0xFF));
                } else if (strncmp(lp, ".short ", 7) == 0) {
                    int64_t v = parse_int(skip_ws(lp + 7));
                    bb_write16le(sec_buf, (uint16_t)(v & 0xFFFF));
                } else if (strncmp(lp, ".long ", 6) == 0) {
                    int64_t v = parse_int(skip_ws(lp + 6));
                    bb_write32le(sec_buf, (uint32_t)(int32_t)v);
                } else if (strncmp(lp, ".quad ", 6) == 0) {
                    int64_t v = parse_int(skip_ws(lp + 6));
                    bb_write64le(sec_buf, (uint64_t)v);
                } else if (strncmp(lp, ".zero ", 6) == 0) {
                    int64_t n = parse_int(skip_ws(lp + 6));
                    for (int64_t i = 0; i < n; i++) bb_write8(sec_buf, 0);
                } else if (strncmp(lp, ".asciz ", 7) == 0) {
                    /* Parse string literal */
                    const char *s = skip_ws(lp + 7);
                    if (*s == '"') s++;
                    while (*s && *s != '"') {
                        if (*s == '\\' && *(s+1)) {
                            s++;
                            switch (*s) {
                            case 'n':  bb_write8(sec_buf, '\n'); break;
                            case 't':  bb_write8(sec_buf, '\t'); break;
                            case 'r':  bb_write8(sec_buf, '\r'); break;
                            case '0':  bb_write8(sec_buf, '\0'); break;
                            case '\\': bb_write8(sec_buf, '\\'); break;
                            case '"':  bb_write8(sec_buf, '"'); break;
                            default:   bb_write8(sec_buf, *s); break;
                            }
                        } else {
                            bb_write8(sec_buf, (uint8_t)*s);
                        }
                        s++;
                    }
                    bb_write8(sec_buf, 0); /* NUL terminator */
                } else if (strncmp(lp, ".p2align ", 9) == 0) {
                    int n = (int)parse_int(skip_ws(lp + 9));
                    int align = 1 << n;
                    bb_align(sec_buf, (size_t)align);
                }
            } else if (cur_sec == SEC_BSS) {
                if (strncmp(lp, ".zero ", 6) == 0) {
                    m->bss_size += (size_t)parse_int(skip_ws(lp + 6));
                }
            }
            continue;
        }

        /* Label definition (ends with ':') */
        {
            const char *q = lp;
            char lname[256]; int ln = 0;
            while (*q && *q != ':' && *q != ' ' && *q != '\t' && ln < 255) lname[ln++] = *q++;
            lname[ln] = 0;
            if (*q == ':') {
                /* Check if it matches a .type @function we saw */
                if (strcmp(lname, pending_type_func) == 0) {
                    /* New function symbol */
                    if (in_function) {
                        ctx_free(&ctx);
                        ctx_init(&ctx);
                    }
                    in_function = 1;
                    fn_start = m->text.size;

                    ElfSym sym = {0};
                    strncpy(sym.name, lname, 255);
                    sym.shndx   = 0; /* will be filled as .text idx */
                    sym.value   = (uint64_t)m->text.size;
                    sym.size    = 0; /* filled later */
                    /* Binding follows .globl only. .type @function is emitted for
                     * BOTH exported and `static` functions (it declares the symbol
                     * type, not its linkage), so it must NOT force STB_GLOBAL —
                     * otherwise a static function is wrongly exported (e.g. into a
                     * shared object's .dynsym). */
                    sym.bind    = (strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                    sym.type    = STT_FUNC;
                    sym.defined = 1;
                    symarr_push(&m->syms, &sym);
                    pending_type_func[0] = 0;
                } else {
                    /* Local label inside function */
                    if (in_function) {
                        ctx_add_label(&ctx, lname, (int32_t)(m->text.size - fn_start));
                        /* Patch forward jumps */
                        for (int i = 0; i < ctx.patch_count; i++) {
                            if (strcmp(ctx.patches[i].label, lname) == 0) {
                                size_t off = ctx.patches[i].patch_off;
                                int32_t target = (int32_t)(m->text.size - fn_start);
                                int32_t disp   = target - (int32_t)(off - fn_start + 4);
                                bb_patch32le(&m->text, off, (uint32_t)disp);
                            }
                        }
                    } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                        /* Data label (e.g. string literals) */
                        ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                        ElfSym sym = {0};
                        strncpy(sym.name, lname, 255);
                        sym.shndx   = (cur_sec == SEC_DATA) ? 0 : 0; /* filled later */
                        sym.value   = (uint64_t)sec_buf->size;
                        sym.size    = 0;
                        sym.bind    = (strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                        sym.type    = STT_OBJECT;
                        sym.defined = 1;
                        sym.shndx   = (cur_sec == SEC_DATA) ? 3 : 4; /* placeholder */
                        symarr_push(&m->syms, &sym);
                    }
                }
                continue;
            }
        }

        /* Instruction line — encode if we're in .text */
        if (cur_sec == SEC_TEXT && in_function) {
            x64_encode_line(line, &m->text, &ctx, fn_start, &m->text_relocs);
        }
    }

    if (in_function) {
        /* Finalize last function's size */
        for (int i = m->syms.count - 1; i >= 0; i--) {
            if (m->syms.data[i].type == STT_FUNC && m->syms.data[i].size == 0) {
                m->syms.data[i].size = (uint32_t)(m->text.size - m->syms.data[i].value);
                break;
            }
        }
        ctx_free(&ctx);
    }
}

/* =========================================================================
 * ELF64 object writer
 * ========================================================================= */

/*
 * Section indices (0-based after NULL):
 *   0 = NULL
 *   1 = .text
 *   2 = .data         (omit if empty)
 *   3 = .rodata       (omit if empty)
 *   4 = .bss          (omit if empty)
 *   5 = .rela.text    (omit if no relocs)
 *   6 = .symtab
 *   7 = .strtab
 *   8 = .shstrtab
 *
 * We build section index dynamically.
 */

#define SHDR64_SIZE 64
#define EHDR64_SIZE 64
#define SYM64_SIZE  24

static void write_uleb128(ByteBuf *b, uint64_t val) {
    do {
        uint8_t byte = val & 0x7F;
        val >>= 7;
        if (val != 0) byte |= 0x80;
        bb_write8(b, byte);
    } while (val != 0);
}

static void write_sleb128(ByteBuf *b, int64_t val) {
    bool more = true;
    while (more) {
        uint8_t byte = val & 0x7F;
        val >>= 7;
        if ((val == 0 && !(byte & 0x40)) || (val == -1 && (byte & 0x40))) {
            more = false;
        } else {
            byte |= 0x80;
        }
        bb_write8(b, byte);
    }
}

static void build_debug_line(AsmModel *m, ByteBuf *out, RelocArr *debug_line_relocs) {
    if (m->loc_count == 0) return;

    ByteBuf body;
    bb_init(&body);

    /* DWARF version = 2 */
    bb_write16le(&body, 2);

    /* Prologue length placeholder */
    size_t header_len_offset = body.size;
    bb_write32le(&body, 0);
    size_t prologue_start = body.size;

    bb_write8(&body, 1);    /* minimum_instruction_length */
    bb_write8(&body, 1);    /* default_is_stmt */
    bb_write8(&body, (uint8_t)-5); /* line_base */
    bb_write8(&body, 14);   /* line_range */
    bb_write8(&body, 10);   /* opcode_base = 10 */

    /* Standard opcode lengths (9 bytes) */
    uint8_t std_op_lengths[9] = {0, 1, 1, 1, 1, 0, 0, 0, 1};
    bb_writebytes(&body, std_op_lengths, 9);

    /* Include directories: empty list */
    bb_write8(&body, 0);

    /* File names */
    for (int i = 0; i < m->file_count; i++) {
        bb_writebytes(&body, (const uint8_t*)m->files[i].path, strlen(m->files[i].path) + 1);
        write_uleb128(&body, 0);
        write_uleb128(&body, 0);
        write_uleb128(&body, 0);
    }
    bb_write8(&body, 0); /* terminate file list */

    size_t prologue_end = body.size;
    bb_patch32le(&body, header_len_offset, (uint32_t)(prologue_end - prologue_start));

    /* Line Number Program */
    uint64_t address = 0;
    int file = 1;
    int line = 1;
    int column = 0;

    /* Set initial address to .text symbol via relocation */
    bb_write8(&body, 0);
    write_uleb128(&body, 9);
    bb_write8(&body, 2); /* DW_LNE_set_address */
    size_t reloc_offset = body.size;
    bb_write64le(&body, 0);

    ElfReloc rel = {0};
    strcpy(rel.sym_name, ".text");
    rel.offset = reloc_offset;
    rel.addend = 0;
    rel.type = 1; /* R_X86_64_64 */
    relocarr_push(debug_line_relocs, &rel);

    for (int i = 0; i < m->loc_count; i++) {
        LocEntry *loc = &m->locs[i];

        if (loc->file_id != file) {
            file = loc->file_id;
            bb_write8(&body, 4); /* DW_LNS_set_file */
            write_uleb128(&body, file);
        }

        if (loc->col != column) {
            column = loc->col;
            bb_write8(&body, 5); /* DW_LNS_set_column */
            write_uleb128(&body, column);
        }

        int delta_line = loc->line - line;
        int delta_pc = (int)(loc->offset - address);

        int special_op = (delta_line - (-5)) + (14 * delta_pc) + 10;
        if (special_op >= 10 && special_op <= 255 && delta_line >= -5 && delta_line <= 8) {
            bb_write8(&body, (uint8_t)special_op);
        } else {
            if (delta_pc > 0) {
                bb_write8(&body, 2); /* DW_LNS_advance_pc */
                write_uleb128(&body, delta_pc);
            }
            if (delta_line != 0) {
                bb_write8(&body, 3); /* DW_LNS_advance_line */
                write_sleb128(&body, delta_line);
            }
            bb_write8(&body, 1); /* DW_LNS_copy */
        }

        address = loc->offset;
        line = loc->line;
    }

    /* Terminate sequence */
    bb_write8(&body, 0);
    write_uleb128(&body, 1);
    bb_write8(&body, 1); /* DW_LNE_end_sequence */

    /* Output DWARF section size + body */
    bb_write32le(out, (uint32_t)body.size);
    bb_writebytes(out, body.data, body.size);

    bb_free(&body);
}

static void write_elf64_object(AsmModel *m, ByteBuf *out) {
    /* ---- Strtab ---- */
    Strtab strtab;
    strtab_init(&strtab);

    /* ---- Build symbol table ---- */
    /* Layout: local symbols first (STB_LOCAL), then global (STB_GLOBAL) */
    /* ELF requires sh_info = index of first global symbol */

    /* Assign section indices */
    int shidx_null   = 0;
    int shidx_text   = 1;
    int shidx_data   = (m->data.size   > 0) ? 2 : -1;
    int shidx_rodata = (m->rodata.size > 0) ? (shidx_data >= 0 ? 3 : 2) : -1;
    int shidx_bss    = (m->bss_size    > 0) ? ((shidx_rodata >= 0) ? shidx_rodata + 1 :
                                                 (shidx_data >= 0 ? 3 : 2)) : -1;

    int next_shidx = 2;
    if (shidx_data   >= 0) { shidx_data   = next_shidx++; }
    if (shidx_rodata >= 0) { shidx_rodata = next_shidx++; }
    if (shidx_bss    >= 0) { shidx_bss    = next_shidx++; }

    /* NOTE: this order must match the section-header write order below
     * (.rela.text, .symtab, .debug_line, .rela.debug_line, .strtab, .shstrtab).
     * .symtab is written before the debug sections, so it must be indexed
     * before them too — otherwise .rela.debug_line's sh_link/sh_info point at
     * the wrong sections and ld.lld rejects the object. */
    int shidx_rela   = (m->text_relocs.count > 0) ? next_shidx++ : -1;
    int shidx_symtab = next_shidx++;
    int shidx_debug_line = (m->loc_count > 0) ? next_shidx++ : -1;
    int shidx_rela_debug = (m->loc_count > 0) ? next_shidx++ : -1;
    int shidx_strtab = next_shidx++;
    int shidx_shstr  = next_shidx++;
    int num_sections  = next_shidx;

    (void)shidx_null;

    /* Patch symbol section indices */
    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (!s->defined) continue;
        if (s->type == STT_FUNC)   { s->shndx = (uint32_t)shidx_text; continue; }
        if (s->type == STT_OBJECT) {
            /* Determine which section by placeholder */
            if (s->shndx == 3) s->shndx = (shidx_data >= 0) ? (uint32_t)shidx_data : SHN_UNDEF;
            else if (s->shndx == 4) s->shndx = (shidx_rodata >= 0) ? (uint32_t)shidx_rodata : SHN_UNDEF;
        }
    }

    /* Add STT_FILE symbol and STT_SECTION symbols */
    /* We add them later directly into the symbol table bytes */
    if (m->loc_count > 0) {
        ElfSym sec_text = {0};
        strcpy(sec_text.name, ".text");
        sec_text.shndx = (uint32_t)shidx_text;
        sec_text.value = 0;
        sec_text.size = 0;
        sec_text.bind = STB_LOCAL;
        sec_text.type = STT_SECTION;
        sec_text.defined = 1;
        symarr_push(&m->syms, &sec_text);
    }

    /* Separate local and global user symbols */
    int nlocal = 0, nglobal = 0;
    for (int i = 0; i < m->syms.count; i++) {
        if (m->syms.data[i].bind == STB_LOCAL) nlocal++;
        else nglobal++;
    }

    /* Build symtab bytes */
    ByteBuf symtab_buf;
    bb_init(&symtab_buf);

    /* Symbol 0: null */
    for (int i = 0; i < SYM64_SIZE; i++) bb_write8(&symtab_buf, 0);

    /* Count of local syms including null (for sh_info) */
    int symtab_info = 1; /* null */

    /* Local symbols */
    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (s->bind != STB_LOCAL) continue;
        uint32_t name_off = strtab_add(&strtab, s->name);
        bb_write32le(&symtab_buf, name_off);           /* st_name */
        bb_write8(&symtab_buf, (uint8_t)((s->bind << 4) | (s->type & 0xF))); /* st_info */
        bb_write8(&symtab_buf, STV_DEFAULT);           /* st_other */
        bb_write16le(&symtab_buf, (uint16_t)(s->defined ? s->shndx : SHN_UNDEF)); /* st_shndx */
        bb_write64le(&symtab_buf, s->value);           /* st_value */
        bb_write64le(&symtab_buf, s->size);            /* st_size */
        symtab_info++;
    }

    /* Global symbols */
    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (s->bind != STB_GLOBAL) continue;
        uint32_t name_off = strtab_add(&strtab, s->name);
        bb_write32le(&symtab_buf, name_off);
        bb_write8(&symtab_buf, (uint8_t)((s->bind << 4) | (s->type & 0xF)));
        bb_write8(&symtab_buf, STV_DEFAULT);
        bb_write16le(&symtab_buf, (uint16_t)(s->defined ? s->shndx : SHN_UNDEF));
        bb_write64le(&symtab_buf, s->value);
        bb_write64le(&symtab_buf, s->size);
    }

    /* Add undefined external symbols from relocations */
    for (int i = 0; i < m->text_relocs.count; i++) {
        const char *rname = m->text_relocs.data[i].sym_name;
        /* Check if already in symbol table */
        int found = 0;
        for (int j = 0; j < m->syms.count; j++) {
            if (strcmp(m->syms.data[j].name, rname) == 0) { found = 1; break; }
        }
        if (!found) {
            /* Add UNDEF global symbol */
            uint32_t name_off = strtab_add(&strtab, rname);
            bb_write32le(&symtab_buf, name_off);
            bb_write8(&symtab_buf, (uint8_t)((STB_GLOBAL << 4) | STT_NOTYPE));
            bb_write8(&symtab_buf, STV_DEFAULT);
            bb_write16le(&symtab_buf, SHN_UNDEF);
            bb_write64le(&symtab_buf, 0);
            bb_write64le(&symtab_buf, 0);
            /* Track so we don't add twice */
            ElfSym us = {0};
            strncpy(us.name, rname, 255);
            us.bind = STB_GLOBAL;
            us.type = STT_NOTYPE;
            us.defined = 0;
            symarr_push(&m->syms, &us);
        }
    }

    int num_syms = (int)(symtab_buf.size / SYM64_SIZE);

    /* Build .rela.text */
    ByteBuf rela_buf;
    bb_init(&rela_buf);
    if (m->text_relocs.count > 0) {
        for (int i = 0; i < m->text_relocs.count; i++) {
            ElfReloc *r = &m->text_relocs.data[i];
            /* Find symbol index */
            int sym_idx = 0;
            int sym_num = 1; /* skip null */
            /* iterate symtab in order: local first, then global */
            for (int j = 0; j < m->syms.count; j++) {
                if (m->syms.data[j].bind != STB_LOCAL) continue;
                sym_num++;
                if (strcmp(m->syms.data[j].name, r->sym_name) == 0) {
                    sym_idx = sym_num - 1;
                    break;
                }
            }
            if (sym_idx == 0) {
                sym_num = symtab_info;
                for (int j = 0; j < m->syms.count; j++) {
                    if (m->syms.data[j].bind != STB_GLOBAL) continue;
                    if (strcmp(m->syms.data[j].name, r->sym_name) == 0) {
                        sym_idx = sym_num;
                        break;
                    }
                    sym_num++;
                }
            }

            bb_write64le(&rela_buf, r->offset);           /* r_offset */
            bb_write64le(&rela_buf, ((uint64_t)sym_idx << 32) | r->type); /* r_info */
            bb_write64le(&rela_buf, (uint64_t)(int64_t)r->addend); /* r_addend */
        }
    }

    /* Build DWARF line tables */
    ByteBuf debug_line_buf;
    bb_init(&debug_line_buf);
    RelocArr debug_line_relocs = {NULL, 0, 0};
    if (shidx_debug_line >= 0) {
        build_debug_line(m, &debug_line_buf, &debug_line_relocs);
    }

    ByteBuf rela_debug_buf;
    bb_init(&rela_debug_buf);
    if (shidx_rela_debug >= 0) {
        for (int i = 0; i < debug_line_relocs.count; i++) {
            ElfReloc *r = &debug_line_relocs.data[i];
            int sym_idx = 0;
            int sym_num = 1; /* skip null */
            for (int j = 0; j < m->syms.count; j++) {
                if (m->syms.data[j].bind != STB_LOCAL) continue;
                sym_num++;
                if (strcmp(m->syms.data[j].name, r->sym_name) == 0) {
                    sym_idx = sym_num - 1;
                    break;
                }
            }
            if (sym_idx == 0) {
                sym_num = symtab_info;
                for (int j = 0; j < m->syms.count; j++) {
                    if (m->syms.data[j].bind != STB_GLOBAL) continue;
                    if (strcmp(m->syms.data[j].name, r->sym_name) == 0) {
                        sym_idx = sym_num;
                        break;
                    }
                    sym_num++;
                }
            }
            bb_write64le(&rela_debug_buf, r->offset);
            bb_write64le(&rela_debug_buf, ((uint64_t)sym_idx << 32) | r->type);
            bb_write64le(&rela_debug_buf, (uint64_t)(int64_t)r->addend);
        }
    }

    /* ---- Section name string table (.shstrtab) ---- */
    Strtab shstrtab;
    strtab_init(&shstrtab);
    uint32_t sh_text_name   = strtab_add(&shstrtab, ".text");
    uint32_t sh_data_name   = (shidx_data   >= 0) ? strtab_add(&shstrtab, ".data")   : 0;
    uint32_t sh_rodata_name = (shidx_rodata >= 0) ? strtab_add(&shstrtab, ".rodata") : 0;
    uint32_t sh_bss_name    = (shidx_bss    >= 0) ? strtab_add(&shstrtab, ".bss")    : 0;
    uint32_t sh_rela_name   = (shidx_rela   >= 0) ? strtab_add(&shstrtab, ".rela.text") : 0;
    uint32_t sh_debug_line_name = (shidx_debug_line >= 0) ? strtab_add(&shstrtab, ".debug_line") : 0;
    uint32_t sh_rela_debug_name = (shidx_rela_debug >= 0) ? strtab_add(&shstrtab, ".rela.debug_line") : 0;
    uint32_t sh_symtab_name = strtab_add(&shstrtab, ".symtab");
    uint32_t sh_strtab_name = strtab_add(&shstrtab, ".strtab");
    uint32_t sh_shstr_name  = strtab_add(&shstrtab, ".shstrtab");
    uint32_t sh_null_name   = 0;

    /* ---- Compute layout ---- */
    size_t off = EHDR64_SIZE;
    /* Sections are laid out after the header, before section headers */
    size_t text_off   = off;   off += m->text.size;
    /* Align data sections */
    off = (off + 15) & ~(size_t)15;
    size_t data_off   = off;   if (shidx_data   >= 0) off += m->data.size;
    off = (off + 15) & ~(size_t)15;
    size_t rodata_off = off;   if (shidx_rodata >= 0) off += m->rodata.size;
    /* bss: no file bytes */
    off = (off + 7) & ~(size_t)7;
    size_t rela_off   = off;   if (shidx_rela   >= 0) off += rela_buf.size;
    off = (off + 7) & ~(size_t)7;
    size_t debug_line_off = off; if (shidx_debug_line >= 0) off += debug_line_buf.size;
    off = (off + 7) & ~(size_t)7;
    size_t rela_debug_off = off; if (shidx_rela_debug >= 0) off += rela_debug_buf.size;
    size_t symtab_off = off;   off += symtab_buf.size;
    size_t strtab_off = off;   off += strtab.buf.size;
    size_t shstr_off  = off;   off += shstrtab.buf.size;
    /* Align section headers to 8 bytes */
    off = (off + 7) & ~(size_t)7;
    size_t shdr_off   = off;

    /* ---- Write ELF header ---- */
    /* e_ident */
    bb_write8(out, ELF_MAG0); bb_write8(out, ELF_MAG1);
    bb_write8(out, ELF_MAG2); bb_write8(out, ELF_MAG3);
    bb_write8(out, ELFCLASS64);
    bb_write8(out, ELFDATA2LSB);
    bb_write8(out, EV_CURRENT);
    bb_write8(out, ELFOSABI_NONE);
    for (int i = 0; i < 8; i++) bb_write8(out, 0); /* padding */
    bb_write16le(out, ET_REL);           /* e_type */
    bb_write16le(out, EM_X86_64);        /* e_machine */
    bb_write32le(out, EV_CURRENT);       /* e_version */
    bb_write64le(out, 0);                /* e_entry */
    bb_write64le(out, 0);                /* e_phoff */
    bb_write64le(out, (uint64_t)shdr_off); /* e_shoff */
    bb_write32le(out, 0);                /* e_flags */
    bb_write16le(out, EHDR64_SIZE);      /* e_ehsize */
    bb_write16le(out, 56);               /* e_phentsize */
    bb_write16le(out, 0);                /* e_phnum */
    bb_write16le(out, SHDR64_SIZE);      /* e_shentsize */
    bb_write16le(out, (uint16_t)num_sections); /* e_shnum */
    bb_write16le(out, (uint16_t)shidx_shstr); /* e_shstrndx */

    /* ---- Write section content ---- */
    bb_writebytes(out, m->text.data, m->text.size);
    while (out->size < data_off) bb_write8(out, 0);
    if (shidx_data >= 0)   bb_writebytes(out, m->data.data, m->data.size);
    while (out->size < rodata_off) bb_write8(out, 0);
    if (shidx_rodata >= 0) bb_writebytes(out, m->rodata.data, m->rodata.size);
    /* bss: no bytes */
    while (out->size < rela_off) bb_write8(out, 0);
    if (shidx_rela >= 0)   bb_writebytes(out, rela_buf.data, rela_buf.size);
    while (out->size < debug_line_off) bb_write8(out, 0);
    if (shidx_debug_line >= 0) bb_writebytes(out, debug_line_buf.data, debug_line_buf.size);
    while (out->size < rela_debug_off) bb_write8(out, 0);
    if (shidx_rela_debug >= 0) bb_writebytes(out, rela_debug_buf.data, rela_debug_buf.size);
    bb_writebytes(out, symtab_buf.data, symtab_buf.size);
    bb_writebytes(out, strtab.buf.data, strtab.buf.size);
    bb_writebytes(out, shstrtab.buf.data, shstrtab.buf.size);
    while (out->size < shdr_off) bb_write8(out, 0);

    /* SHN_NULL */
    elf_write_shdr64(out, sh_null_name, SHT_NULL, 0, 0, 0, 0, 0, 0, 0, 0);
    /* .text */
    elf_write_shdr64(out, sh_text_name, SHT_PROGBITS,
           SHF_ALLOC | SHF_EXECINSTR, 0,
           (uint64_t)text_off, (uint64_t)m->text.size,
           0, 0, 16, 0);
    /* .data */
    if (shidx_data >= 0)
        elf_write_shdr64(out, sh_data_name, SHT_PROGBITS,
               SHF_ALLOC | SHF_WRITE, 0,
               (uint64_t)data_off, (uint64_t)m->data.size,
               0, 0, 8, 0);
    /* .rodata */
    if (shidx_rodata >= 0)
        elf_write_shdr64(out, sh_rodata_name, SHT_PROGBITS,
               SHF_ALLOC, 0,
               (uint64_t)rodata_off, (uint64_t)m->rodata.size,
               0, 0, 8, 0);
    /* .bss */
    if (shidx_bss >= 0)
        elf_write_shdr64(out, sh_bss_name, SHT_NOBITS,
               SHF_ALLOC | SHF_WRITE, 0,
               (uint64_t)rodata_off + (shidx_rodata >= 0 ? m->rodata.size : 0),
               (uint64_t)m->bss_size,
               0, 0, 8, 0);
    /* .rela.text */
    if (shidx_rela >= 0)
        elf_write_shdr64(out, sh_rela_name, SHT_RELA,
               0, 0,
               (uint64_t)rela_off, (uint64_t)rela_buf.size,
               (uint32_t)shidx_symtab, (uint32_t)shidx_text, 8, 24);
    /* .symtab */
    elf_write_shdr64(out, sh_symtab_name, SHT_SYMTAB,
           0, 0,
           (uint64_t)symtab_off, (uint64_t)symtab_buf.size,
           (uint32_t)shidx_strtab, (uint32_t)symtab_info, 8, SYM64_SIZE);
    /* .debug_line */
    if (shidx_debug_line >= 0)
        elf_write_shdr64(out, sh_debug_line_name, SHT_PROGBITS,
               0, 0,
               (uint64_t)debug_line_off, (uint64_t)debug_line_buf.size,
               0, 0, 1, 0);
    /* .rela.debug_line */
    if (shidx_rela_debug >= 0)
        elf_write_shdr64(out, sh_rela_debug_name, SHT_RELA,
               0, 0,
               (uint64_t)rela_debug_off, (uint64_t)rela_debug_buf.size,
               (uint32_t)shidx_symtab, (uint32_t)shidx_debug_line, 8, 24);
    /* .strtab */
    elf_write_shdr64(out, sh_strtab_name, SHT_STRTAB,
           0, 0,
           (uint64_t)strtab_off, (uint64_t)strtab.buf.size,
           0, 0, 1, 0);
    /* .shstrtab */
    elf_write_shdr64(out, sh_shstr_name, SHT_STRTAB,
           0, 0,
           (uint64_t)shstr_off, (uint64_t)shstrtab.buf.size,
           0, 0, 1, 0);

    bb_free(&rela_buf);
    bb_free(&symtab_buf);
    if (shidx_debug_line >= 0) {
        bb_free(&debug_line_buf);
    }
    if (shidx_rela_debug >= 0) {
        bb_free(&rela_debug_buf);
        free(debug_line_relocs.data);
    }
    strtab_free(&strtab);
    strtab_free(&shstrtab);

    (void)nlocal; (void)nglobal; (void)num_syms;
}

/* =========================================================================
 * i386 instruction encoder and ELF32 writer
 *
 * This covers the exact GNU AS dialect emitted by backend_i386.c. It mirrors
 * the x86_64 encoder above but emits 32-bit encodings and SHT_REL relocations.
 * ========================================================================= */

#define EHDR32_SIZE 52
#define SHDR32_SIZE 40
#define SYM32_SIZE  16

static const char *parse_symbol_name(const char *p, char *out, size_t out_size) {
    size_t n = 0;
    while (*p && *p != ',' && *p != '\n' && *p != ' ' && *p != '\t' && *p != '(' && n + 1 < out_size) {
        out[n++] = *p++;
    }
    out[n] = 0;
    return p;
}

static void i386_emit_modrm_mem(ByteBuf *out, int reg, const Operand *mem, uint8_t op,
                                RelocArr *relocs, int reloc_type) {
    if (op != 0) bb_write8(out, op);

    if (mem->type == OT_SYM) {
        bb_write8(out, modrm_r0(reg & 7, 5));
        ElfReloc rel = {0};
        strncpy(rel.sym_name, mem->sym, sizeof(rel.sym_name) - 1);
        rel.offset = out->size;
        rel.type = reloc_type;
        rel.addend = 0;
        relocarr_push(relocs, &rel);
        bb_write32le(out, 0);
        return;
    }

    if (mem->type == OT_MEM_IDX) {
        int scale_log2 = (mem->scale == 2) ? 1 : (mem->scale == 4) ? 2 : (mem->scale == 8) ? 3 : 0;
        bb_write8(out, (uint8_t)(0x00 | ((reg & 7) << 3) | 0x04));
        bb_write8(out, sib_byte(scale_log2, mem->idx, mem->base));
        return;
    }

    int base = mem->base;
    int rb = base & 7;
    int32_t disp = (int32_t)mem->imm;

    /* GOT-relative: symbol@GOT(%reg) — use R_386_GOT32 relocation */
    if (mem->is_gotpcrel && mem->sym[0]) {
        bb_write8(out, modrm_r0(reg & 7, rb));
        ElfReloc rel = {0};
        strncpy(rel.sym_name, mem->sym, sizeof(rel.sym_name) - 1);
        rel.offset = out->size;
        rel.type = R_386_GOT32;
        rel.addend = -4;
        relocarr_push(relocs, &rel);
        bb_write32le(out, 0);
        return;
    }

    if (disp == 0 && rb != 5) {
        bb_write8(out, modrm_r0(reg & 7, rb));
        if (rb == 4) bb_write8(out, 0x24);
    } else if (disp >= -128 && disp <= 127) {
        bb_write8(out, modrm_r8(reg & 7, rb));
        if (rb == 4) bb_write8(out, 0x24);
        bb_write8(out, (uint8_t)(int8_t)disp);
    } else {
        bb_write8(out, modrm_r32(reg & 7, rb));
        if (rb == 4) bb_write8(out, 0x24);
        bb_write32le(out, (uint32_t)disp);
    }
}

static Operand parse_operand_i386(const char **pp) {
    Operand op = {0};
    op.type = OT_NONE;
    const char *p = skip_ws(*pp);

    if (*p == '$') {
        p++;
        op.type = OT_IMM;
        if (*p == '-' || isdigit((unsigned char)*p)) {
            char buf[64];
            int n = 0;
            if (*p == '-') buf[n++] = *p++;
            while (*p && *p != ',' && *p != '\n' && *p != ' ' && *p != '\t' && n < 63)
                buf[n++] = *p++;
            buf[n] = 0;
            op.imm = parse_int(buf);
        } else {
            p = parse_symbol_name(p, op.sym, sizeof(op.sym));
        }
        *pp = p;
        return op;
    }

    if (*p == '%') {
        char reg[16];
        int n = 0;
        while (*p && *p != ',' && *p != ')' && *p != '\n' && *p != ' ' && *p != '\t' && n < 15)
            reg[n++] = *p++;
        reg[n] = 0;
        op.type = reg_optype(reg);
        op.reg = x64_reg_num(reg);
        *pp = p;
        return op;
    }

    if (*p == '(') {
        p++;
        char base[16]; int nb = 0;
        while (*p && *p != ',' && *p != ')' && nb < 15) base[nb++] = *p++;
        base[nb] = 0;
        op.base = x64_reg_num(base);
        if (*p == ',') {
            p++;
            char idx[16]; int ni = 0;
            while (*p && *p != ',' && *p != ')' && ni < 15) idx[ni++] = *p++;
            idx[ni] = 0;
            op.idx = x64_reg_num(idx);
            if (*p == ',') {
                p++;
                op.scale = (int)strtol(p, (char **)&p, 10);
            }
        }
        if (*p == ')') p++;
        op.type = (op.scale != 0) ? OT_MEM_IDX : OT_MEM_INDIR;
        *pp = p;
        return op;
    }

    if (*p == '-' || isdigit((unsigned char)*p)) {
        char buf[64];
        int n = 0;
        if (*p == '-') buf[n++] = *p++;
        while (isdigit((unsigned char)*p) && n < 63) buf[n++] = *p++;
        buf[n] = 0;
        int64_t disp = parse_int(buf);
        if (*p == '(') {
            p++;
            char base[16]; int nb = 0;
            while (*p && *p != ')' && *p != ',' && nb < 15) base[nb++] = *p++;
            base[nb] = 0;
            if (*p == ')') p++;
            op.type = OT_MEM_BASE;
            op.base = x64_reg_num(base);
            op.imm = disp;
            *pp = p;
            return op;
        }
        op.type = OT_IMM;
        op.imm = disp;
        *pp = p;
        return op;
    }

    if (*p && *p != ',' && *p != '\n') {
        p = parse_symbol_name(p, op.sym, sizeof(op.sym));
        const char *got_suffix = strstr(op.sym, "@GOT");
        if (got_suffix && *p == '(') {
            /* symbol@GOT(%reg) — GOT-relative addressing */
            int sym_len = (int)(got_suffix - op.sym);
            op.sym[sym_len] = 0;
            op.is_gotpcrel = 1;
            p++;
            char base[16]; int nb = 0;
            while (*p && *p != ')' && nb < 15) base[nb++] = *p++;
            base[nb] = 0;
            op.base = x64_reg_num(base);
            if (*p == ')') p++;
            op.type = OT_MEM_BASE;
            op.imm = 0;
        } else if (got_suffix) {
            /* plain symbol@GOT without (reg) — strip suffix, keep as symbol */
            int sym_len = (int)(got_suffix - op.sym);
            op.sym[sym_len] = 0;
            op.type = OT_SYM;
            op.is_gotpcrel = 1;
        } else {
            op.type = OT_SYM;
        }
        *pp = p;
        return op;
    }

    *pp = p;
    return op;
}

static void i386_emit_group1(ByteBuf *text, uint8_t op_rr, int slash, Operand src, Operand dst) {
    if (src.type == OT_IMM && dst.type == OT_REG32) {
        if (src.imm >= -128 && src.imm <= 127) {
            bb_write8(text, 0x83);
            bb_write8(text, modrm_rr(slash, dst.reg));
            bb_write8(text, (uint8_t)(int8_t)src.imm);
        } else {
            bb_write8(text, 0x81);
            bb_write8(text, modrm_rr(slash, dst.reg));
            bb_write32le(text, (uint32_t)(int32_t)src.imm);
        }
    } else if (src.type == OT_REG32 && dst.type == OT_REG32) {
        bb_write8(text, op_rr);
        bb_write8(text, modrm_rr(src.reg, dst.reg));
    }
}

static int i386_encode_line(const char *line, ByteBuf *text, EncCtx *ctx,
                            size_t fn_start, RelocArr *relocs) {
    const char *p = skip_ws(line);
    if (!*p || *p == '\n' || *p == '#') return 0;
    if (*p == '.') return 0;

    {
        const char *q = p;
        char lname[256]; int ln = 0;
        while (*q && *q != ':' && *q != ' ' && *q != '\n' && ln < 255)
            lname[ln++] = *q++;
        lname[ln] = 0;
        if (*q == ':') {
            ctx_add_label(ctx, lname, (int32_t)(text->size - fn_start));
            for (int i = 0; i < ctx->patch_count; i++) {
                if (strcmp(ctx->patches[i].label, lname) == 0) {
                    size_t off = ctx->patches[i].patch_off;
                    int32_t target = (int32_t)(text->size - fn_start);
                    int32_t disp = target - (int32_t)(off - fn_start + 4);
                    bb_patch32le(text, off, (uint32_t)disp);
                }
            }
            return 0;
        }
    }

    char mnem[32]; int mn = 0;
    while (*p && *p != ' ' && *p != '\t' && *p != '\n' && mn < 31)
        mnem[mn++] = *p++;
    mnem[mn] = 0;
    p = skip_ws(p);

    if (strcmp(mnem, "pushl") == 0) {
        Operand op = parse_operand_i386(&p);
        if (op.type == OT_REG32) {
            bb_write8(text, (uint8_t)(0x50 | (op.reg & 7)));
        } else if (op.type == OT_IMM && op.sym[0]) {
            bb_write8(text, 0x68);
            ElfReloc rel = {0};
            strncpy(rel.sym_name, op.sym, sizeof(rel.sym_name) - 1);
            rel.offset = text->size;
            rel.type = R_386_32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
        } else if (op.type == OT_IMM) {
            if (op.imm >= -128 && op.imm <= 127) {
                bb_write8(text, 0x6A);
                bb_write8(text, (uint8_t)(int8_t)op.imm);
            } else {
                bb_write8(text, 0x68);
                bb_write32le(text, (uint32_t)(int32_t)op.imm);
            }
        }
        return 1;
    }

    if (strcmp(mnem, "popl") == 0) {
        Operand op = parse_operand_i386(&p);
        bb_write8(text, (uint8_t)(0x58 | (op.reg & 7)));
        return 1;
    }

    if (strcmp(mnem, "leave") == 0) { bb_write8(text, 0xC9); return 1; }
    if (strcmp(mnem, "ret") == 0) {
        p = skip_ws(p);
        if (*p == '$') {
            Operand imm = parse_operand_i386(&p);
            bb_write8(text, 0xC2);
            bb_write16le(text, (uint16_t)imm.imm);
        } else {
            bb_write8(text, 0xC3);
        }
        return 1;
    }
    if (strcmp(mnem, "cltd") == 0) { bb_write8(text, 0x99); return 1; }

    if (strcmp(mnem, "movl") == 0 || strcmp(mnem, "movw") == 0 || strcmp(mnem, "movb") == 0) {
        int is_word = strcmp(mnem, "movw") == 0;
        int is_byte = strcmp(mnem, "movb") == 0;
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        if (is_word) bb_write8(text, 0x66);

        if (src.type == OT_IMM && dst.type == OT_REG32 && !is_byte && !is_word) {
            bb_write8(text, (uint8_t)(0xB8 | (dst.reg & 7)));
            if (src.sym[0]) {
                ElfReloc rel = {0};
                strncpy(rel.sym_name, src.sym, sizeof(rel.sym_name) - 1);
                rel.offset = text->size;
                rel.type = R_386_32;
                relocarr_push(relocs, &rel);
                bb_write32le(text, 0);
            } else {
                bb_write32le(text, (uint32_t)(int32_t)src.imm);
            }
            return 1;
        }
        if ((src.type == OT_REG32 || src.type == OT_REG16 || src.type == OT_REG8) &&
            (dst.type == OT_REG32 || dst.type == OT_REG16 || dst.type == OT_REG8)) {
            bb_write8(text, is_byte ? 0x88 : 0x89);
            bb_write8(text, modrm_rr(src.reg, dst.reg));
            return 1;
        }
        if ((src.type == OT_REG32 || src.type == OT_REG16 || src.type == OT_REG8) &&
            (dst.type == OT_MEM_BASE || dst.type == OT_MEM_INDIR || dst.type == OT_MEM_IDX || dst.type == OT_SYM)) {
            i386_emit_modrm_mem(text, src.reg, &dst, is_byte ? 0x88 : 0x89, relocs, R_386_32);
            return 1;
        }
        if ((src.type == OT_MEM_BASE || src.type == OT_MEM_INDIR || src.type == OT_MEM_IDX || src.type == OT_SYM) &&
            (dst.type == OT_REG32 || dst.type == OT_REG16 || dst.type == OT_REG8)) {
            i386_emit_modrm_mem(text, dst.reg, &src, is_byte ? 0x8A : 0x8B, relocs, R_386_32);
            return 1;
        }
        diagnostics_fatal("elf_writer: unsupported i386 mov form");
    }

    if (strcmp(mnem, "movsbl") == 0 || strcmp(mnem, "movswl") == 0 || strcmp(mnem, "movzbl") == 0) {
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        if (strcmp(mnem, "movswl") == 0) {
            bb_write8(text, 0x0F); bb_write8(text, 0xBF);
        } else {
            bb_write8(text, 0x0F); bb_write8(text, strcmp(mnem, "movzbl") == 0 ? 0xB6 : 0xBE);
        }
        if (src.type == OT_REG8 || src.type == OT_REG16 || src.type == OT_REG32) {
            bb_write8(text, modrm_rr(dst.reg, src.reg));
        } else {
            i386_emit_modrm_mem(text, dst.reg, &src, 0, relocs, R_386_32);
        }
        return 1;
    }

    if (strcmp(mnem, "addl") == 0 || strcmp(mnem, "subl") == 0 ||
        strcmp(mnem, "andl") == 0 || strcmp(mnem, "orl") == 0 || strcmp(mnem, "xorl") == 0 ||
        strcmp(mnem, "cmpl") == 0) {
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        int slash = strcmp(mnem, "addl") == 0 ? 0 : strcmp(mnem, "orl") == 0 ? 1 :
                    strcmp(mnem, "andl") == 0 ? 4 : strcmp(mnem, "subl") == 0 ? 5 :
                    strcmp(mnem, "xorl") == 0 ? 6 : 7;
        uint8_t op_rr = strcmp(mnem, "addl") == 0 ? 0x01 : strcmp(mnem, "orl") == 0 ? 0x09 :
                        strcmp(mnem, "andl") == 0 ? 0x21 : strcmp(mnem, "subl") == 0 ? 0x29 :
                        strcmp(mnem, "xorl") == 0 ? 0x31 : 0x39;
        i386_emit_group1(text, op_rr, slash, src, dst);
        return 1;
    }

    if (strcmp(mnem, "imull") == 0) {
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        bb_write8(text, 0x0F); bb_write8(text, 0xAF); bb_write8(text, modrm_rr(dst.reg, src.reg));
        return 1;
    }
    if (strcmp(mnem, "idivl") == 0) {
        Operand op = parse_operand_i386(&p);
        bb_write8(text, 0xF7); bb_write8(text, modrm_rr(7, op.reg));
        return 1;
    }
    if (strcmp(mnem, "notl") == 0 || strcmp(mnem, "negl") == 0) {
        Operand op = parse_operand_i386(&p);
        bb_write8(text, 0xF7); bb_write8(text, modrm_rr(strcmp(mnem, "notl") == 0 ? 2 : 3, op.reg));
        return 1;
    }
    if (strcmp(mnem, "shll") == 0 || strcmp(mnem, "sarl") == 0 || strcmp(mnem, "shrl") == 0) {
        int slash = strcmp(mnem, "shll") == 0 ? 4 : strcmp(mnem, "shrl") == 0 ? 5 : 7;
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        if (src.type == OT_IMM) {
            bb_write8(text, src.imm == 1 ? 0xD1 : 0xC1);
            bb_write8(text, modrm_rr(slash, dst.reg));
            if (src.imm != 1) bb_write8(text, (uint8_t)src.imm);
        } else {
            bb_write8(text, 0xD3);
            bb_write8(text, modrm_rr(slash, dst.reg));
        }
        return 1;
    }

    if (strncmp(mnem, "set", 3) == 0) {
        uint8_t op2;
        if      (strcmp(mnem+3, "e")   == 0) op2 = 0x94;
        else if (strcmp(mnem+3, "ne")  == 0) op2 = 0x95;
        else if (strcmp(mnem+3, "l")   == 0) op2 = 0x9C;
        else if (strcmp(mnem+3, "g")   == 0) op2 = 0x9F;
        else if (strcmp(mnem+3, "le")  == 0) op2 = 0x9E;
        else if (strcmp(mnem+3, "ge")  == 0) op2 = 0x9D;
        else if (strcmp(mnem+3, "b")   == 0) op2 = 0x92;
        else if (strcmp(mnem+3, "a")   == 0) op2 = 0x97;
        else if (strcmp(mnem+3, "be")  == 0) op2 = 0x96;
        else                                  op2 = 0x93;
        Operand op = parse_operand_i386(&p);
        bb_write8(text, 0x0F); bb_write8(text, op2); bb_write8(text, modrm_rr(0, op.reg));
        return 1;
    }

    if (strcmp(mnem, "leal") == 0) {
        Operand src = parse_operand_i386(&p);
        if (*p == ',') p++;
        Operand dst = parse_operand_i386(&p);
        i386_emit_modrm_mem(text, dst.reg, &src, 0x8D, relocs, R_386_32);
        return 1;
    }

    if (strcmp(mnem, "call") == 0) {
        if (*p == '*') {
            p++;
            Operand op = parse_operand_i386(&p);
            bb_write8(text, 0xFF); bb_write8(text, modrm_rr(2, op.reg));
        } else {
            char sym[256];
            parse_symbol_name(p, sym, sizeof(sym));
            bb_write8(text, 0xE8);
            ElfReloc rel = {0};
            int use_plt = 0;
            const char *plt = strstr(sym, "@PLT");
            if (plt) {
                int sym_len = (int)(plt - sym);
                strncpy(rel.sym_name, sym, sym_len > 255 ? 255 : (size_t)sym_len);
                rel.sym_name[sym_len] = 0;
                use_plt = 1;
            } else {
                strncpy(rel.sym_name, sym, sizeof(rel.sym_name) - 1);
            }
            rel.offset = text->size;
            rel.type = use_plt ? R_386_PLT32 : R_386_PC32;
            relocarr_push(relocs, &rel);
            bb_write32le(text, 0);
        }
        return 1;
    }

    if (strcmp(mnem, "je") == 0 || strcmp(mnem, "jmp") == 0) {
        char label[64]; int nl = 0;
        while (*p && *p != '\n' && *p != ' ' && *p != '\t' && nl < 63) label[nl++] = *p++;
        label[nl] = 0;
        int is_je = strcmp(mnem, "je") == 0;
        int32_t target_off = ctx_find_label(ctx, label);
        if (is_je) { bb_write8(text, 0x0F); bb_write8(text, 0x84); }
        else bb_write8(text, 0xE9);
        if (target_off >= 0) {
            int32_t here = (int32_t)(text->size - fn_start + 4);
            bb_write32le(text, (uint32_t)(target_off - here));
        } else {
            ctx_add_patch(ctx, text->size, label);
            bb_write32le(text, 0);
        }
        return 1;
    }

    char msg[160];
    snprintf(msg, sizeof(msg), "elf_writer: unsupported i386 instruction %s", mnem);
    diagnostics_fatal(msg);
    return 0;
}

static void parse_asm_i386(const char *asm_text, const char *src_path, AsmModel *m) {
    (void)src_path;
    SectionId cur_sec = SEC_NONE;
    const char *p = asm_text;
    EncCtx ctx; ctx_init(&ctx);
    size_t fn_start = 0;
    int in_function = 0;
    char pending_globl[256] = "";
    char pending_type_func[256] = "";

    while (*p) {
        const char *line_start = p;
        const char *line_end = p;
        while (*line_end && *line_end != '\n') line_end++;
        char line[1024];
        int linelen = (int)(line_end - line_start);
        if (linelen > 1023) linelen = 1023;
        memcpy(line, line_start, linelen);
        line[linelen] = 0;
        p = (*line_end == '\n') ? line_end + 1 : line_end;

        const char *lp = skip_ws(line);
        if (!*lp || *lp == '#') continue;
        if (strcmp(lp, ".text") == 0) { cur_sec = SEC_TEXT; continue; }
        if (strcmp(lp, ".data") == 0) { cur_sec = SEC_DATA; continue; }
        if (strcmp(lp, ".section .rodata") == 0 || strcmp(lp, ".rodata") == 0 ||
            strncmp(lp, ".section\t.rodata", 16) == 0 || strncmp(lp, ".section .rodata", 16) == 0) {
            cur_sec = SEC_RODATA; continue;
        }
        if (strcmp(lp, ".bss") == 0) { cur_sec = SEC_BSS; continue; }
        if (strncmp(lp, ".globl ", 7) == 0 || strncmp(lp, ".global ", 8) == 0) {
            const char *s = lp + (lp[6] == ' ' ? 7 : 8);
            strncpy(pending_globl, skip_ws(s), sizeof(pending_globl) - 1);
            continue;
        }
        if (strncmp(lp, ".type ", 6) == 0) {
            const char *s = skip_ws(lp + 6);
            char tname[256]; int tn = 0;
            while (*s && *s != ',' && tn < 255) tname[tn++] = *s++;
            tname[tn] = 0;
            if (strstr(s, "@function")) strncpy(pending_type_func, tname, sizeof(pending_type_func) - 1);
            continue;
        }

        if (*lp == '.') {
            const char *q = lp;
            char lname[256]; int ln = 0;
            while (*q && *q != ':' && *q != ' ' && *q != '\t' && ln < 255) lname[ln++] = *q++;
            lname[ln] = 0;
            if (*q == ':') {
                if (in_function && cur_sec == SEC_TEXT) {
                    ctx_add_label(&ctx, lname, (int32_t)(m->text.size - fn_start));
                    for (int i = 0; i < ctx.patch_count; i++) {
                        if (strcmp(ctx.patches[i].label, lname) == 0) {
                            size_t off = ctx.patches[i].patch_off;
                            int32_t target = (int32_t)(m->text.size - fn_start);
                            int32_t disp = target - (int32_t)(off - fn_start + 4);
                            bb_patch32le(&m->text, off, (uint32_t)disp);
                        }
                    }
                } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                    ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                    ElfSym sym = {0};
                    strncpy(sym.name, lname, sizeof(sym.name) - 1);
                    sym.shndx = (cur_sec == SEC_DATA) ? 3 : 4;
                    sym.value = (uint64_t)sec_buf->size;
                    sym.bind = (strlen(pending_globl) > 0 && strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                    sym.type = STT_OBJECT;
                    sym.defined = 1;
                    symarr_push(&m->syms, &sym);
                }
                continue;
            }
        }

        if (*lp == '.') {
            if (strncmp(lp, ".file ", 6) == 0) {
                const char *s = skip_ws(lp + 6);
                int id = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                char path[256] = "";
                if (*s == '"') {
                    s++;
                    int pi = 0;
                    while (*s && *s != '"' && pi < 255) path[pi++] = *s++;
                    path[pi] = 0;
                }
                if (m->file_count == m->file_cap) {
                    m->file_cap = m->file_cap ? m->file_cap * 2 : 4;
                    m->files = realloc(m->files, sizeof(FileEntry) * m->file_cap);
                }
                m->files[m->file_count].id = id;
                strncpy(m->files[m->file_count].path, path, 255);
                m->file_count++;
            } else if (strncmp(lp, ".loc ", 5) == 0) {
                const char *s = skip_ws(lp + 5);
                int file_id = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                int line = (int)strtol(s, (char**)&s, 10);
                s = skip_ws(s);
                int col = (int)strtol(s, (char**)&s, 10);
                if (cur_sec == SEC_TEXT) {
                    if (m->loc_count == m->loc_cap) {
                        m->loc_cap = m->loc_cap ? m->loc_cap * 2 : 32;
                        m->locs = realloc(m->locs, sizeof(LocEntry) * m->loc_cap);
                    }
                    m->locs[m->loc_count].file_id = file_id;
                    m->locs[m->loc_count].line = line;
                    m->locs[m->loc_count].col = col;
                    m->locs[m->loc_count].offset = m->text.size;
                    m->loc_count++;
                }
            } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                if (strncmp(lp, ".byte ", 6) == 0) bb_write8(sec_buf, (uint8_t)(parse_int(skip_ws(lp + 6)) & 0xff));
                else if (strncmp(lp, ".short ", 7) == 0) bb_write16le(sec_buf, (uint16_t)(parse_int(skip_ws(lp + 7)) & 0xffff));
                else if (strncmp(lp, ".long ", 6) == 0) bb_write32le(sec_buf, (uint32_t)(int32_t)parse_int(skip_ws(lp + 6)));
                else if (strncmp(lp, ".quad ", 6) == 0) bb_write64le(sec_buf, (uint64_t)parse_int(skip_ws(lp + 6)));
                else if (strncmp(lp, ".zero ", 6) == 0) {
                    int64_t n = parse_int(skip_ws(lp + 6));
                    for (int64_t i = 0; i < n; i++) bb_write8(sec_buf, 0);
                } else if (strncmp(lp, ".asciz ", 7) == 0) {
                    const char *s = skip_ws(lp + 7);
                    if (*s == '"') s++;
                    while (*s && *s != '"') {
                        if (*s == '\\' && *(s + 1)) {
                            s++;
                            switch (*s) {
                            case 'n': bb_write8(sec_buf, '\n'); break;
                            case 't': bb_write8(sec_buf, '\t'); break;
                            case 'r': bb_write8(sec_buf, '\r'); break;
                            case '0': bb_write8(sec_buf, '\0'); break;
                            case '\\': bb_write8(sec_buf, '\\'); break;
                            case '"': bb_write8(sec_buf, '"'); break;
                            default: bb_write8(sec_buf, *s); break;
                            }
                        } else {
                            bb_write8(sec_buf, (uint8_t)*s);
                        }
                        s++;
                    }
                    bb_write8(sec_buf, 0);
                } else if (strncmp(lp, ".p2align ", 9) == 0) {
                    bb_align(sec_buf, (size_t)1 << (int)parse_int(skip_ws(lp + 9)));
                }
            } else if (cur_sec == SEC_BSS && strncmp(lp, ".zero ", 6) == 0) {
                m->bss_size += (size_t)parse_int(skip_ws(lp + 6));
            }
            continue;
        }

        const char *q = lp;
        char lname[256]; int ln = 0;
        while (*q && *q != ':' && *q != ' ' && *q != '\t' && ln < 255) lname[ln++] = *q++;
        lname[ln] = 0;
        if (*q == ':') {
            if (strcmp(lname, pending_type_func) == 0) {
                if (in_function) { ctx_free(&ctx); ctx_init(&ctx); }
                in_function = 1;
                fn_start = m->text.size;
                ElfSym sym = {0};
                strncpy(sym.name, lname, sizeof(sym.name) - 1);
                sym.value = (uint64_t)m->text.size;
                sym.bind = (strlen(pending_globl) > 0 && strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                sym.type = STT_FUNC;
                sym.defined = 1;
                symarr_push(&m->syms, &sym);
                pending_type_func[0] = 0;
            } else if (in_function && cur_sec == SEC_TEXT) {
                i386_encode_line(line, &m->text, &ctx, fn_start, &m->text_relocs);
            } else if (cur_sec == SEC_DATA || cur_sec == SEC_RODATA) {
                ByteBuf *sec_buf = (cur_sec == SEC_DATA) ? &m->data : &m->rodata;
                ElfSym sym = {0};
                strncpy(sym.name, lname, sizeof(sym.name) - 1);
                sym.shndx = (cur_sec == SEC_DATA) ? 3 : 4;
                sym.value = (uint64_t)sec_buf->size;
                sym.bind = (strlen(pending_globl) > 0 && strcmp(lname, pending_globl) == 0) ? STB_GLOBAL : STB_LOCAL;
                sym.type = STT_OBJECT;
                sym.defined = 1;
                symarr_push(&m->syms, &sym);
            }
            continue;
        }

        if (cur_sec == SEC_TEXT && in_function) {
            i386_encode_line(line, &m->text, &ctx, fn_start, &m->text_relocs);
        }
    }

    if (in_function) {
        for (int i = m->syms.count - 1; i >= 0; i--) {
            if (m->syms.data[i].type == STT_FUNC && m->syms.data[i].size == 0) {
                m->syms.data[i].size = (uint32_t)(m->text.size - m->syms.data[i].value);
                break;
            }
        }
        ctx_free(&ctx);
    }
}

static int sym_index32(AsmModel *m, const char *name, int symtab_info) {
    int sym_num = 1;
    for (int j = 0; j < m->syms.count; j++) {
        if (m->syms.data[j].bind != STB_LOCAL) continue;
        if (strcmp(m->syms.data[j].name, name) == 0) return sym_num;
        sym_num++;
    }
    sym_num = symtab_info;
    for (int j = 0; j < m->syms.count; j++) {
        if (m->syms.data[j].bind != STB_GLOBAL) continue;
        if (strcmp(m->syms.data[j].name, name) == 0) return sym_num;
        sym_num++;
    }
    return 0;
}

static void write_elf32_object(AsmModel *m, ByteBuf *out) {
    int shidx_text = 1;
    int next_shidx = 2;
    int shidx_data = (m->data.size > 0) ? next_shidx++ : -1;
    int shidx_rodata = (m->rodata.size > 0) ? next_shidx++ : -1;
    int shidx_bss = (m->bss_size > 0) ? next_shidx++ : -1;
    int shidx_rel = (m->text_relocs.count > 0) ? next_shidx++ : -1;
    int shidx_symtab = next_shidx++;
    int shidx_strtab = next_shidx++;
    int shidx_shstr = next_shidx++;
    int num_sections = next_shidx;

    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (!s->defined) continue;
        if (s->type == STT_FUNC) s->shndx = (uint32_t)shidx_text;
        else if (s->type == STT_OBJECT) {
            if (s->shndx == 3) s->shndx = (shidx_data >= 0) ? (uint32_t)shidx_data : SHN_UNDEF;
            else if (s->shndx == 4) s->shndx = (shidx_rodata >= 0) ? (uint32_t)shidx_rodata : SHN_UNDEF;
        }
    }

    Strtab strtab;
    strtab_init(&strtab);

    Strtab shstrtab;
    strtab_init(&shstrtab);
    uint32_t sh_null_name   = 0;
    uint32_t sh_text_name   = strtab_add(&shstrtab, ".text");
    uint32_t sh_data_name   = (shidx_data >= 0) ? strtab_add(&shstrtab, ".data") : 0;
    uint32_t sh_rodata_name = (shidx_rodata >= 0) ? strtab_add(&shstrtab, ".rodata") : 0;
    uint32_t sh_bss_name    = (shidx_bss >= 0) ? strtab_add(&shstrtab, ".bss") : 0;
    uint32_t sh_rel_name    = (shidx_rel >= 0) ? strtab_add(&shstrtab, ".rel.text") : 0;
    uint32_t sh_symtab_name = strtab_add(&shstrtab, ".symtab");
    uint32_t sh_strtab_name = strtab_add(&shstrtab, ".strtab");
    uint32_t sh_shstr_name  = strtab_add(&shstrtab, ".shstrtab");

    /* Build simple symtab: null + defined locals + globals */
    ByteBuf symtab_buf;
    bb_init(&symtab_buf);
    for (int i = 0; i < SYM32_SIZE; i++) bb_write8(&symtab_buf, 0); /* null */
    int symtab_info = 1;

    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (s->bind != STB_LOCAL) continue;
        uint32_t no = strtab_add(&strtab, s->name);
        bb_write32le(&symtab_buf, no);           /* st_name */
        bb_write32le(&symtab_buf, (uint32_t)s->value); /* st_value */
        bb_write32le(&symtab_buf, s->size);      /* st_size */
        bb_write8(&symtab_buf, (uint8_t)((s->bind << 4) | (s->type & 0xF)));
        bb_write8(&symtab_buf, STV_DEFAULT);
        bb_write16le(&symtab_buf, (uint16_t)(s->defined ? s->shndx : SHN_UNDEF));
        symtab_info++;
    }
    for (int i = 0; i < m->syms.count; i++) {
        ElfSym *s = &m->syms.data[i];
        if (s->bind != STB_GLOBAL) continue;
        uint32_t no = strtab_add(&strtab, s->name);
        bb_write32le(&symtab_buf, no);
        bb_write32le(&symtab_buf, (uint32_t)s->value);
        bb_write32le(&symtab_buf, s->size);
        bb_write8(&symtab_buf, (uint8_t)((s->bind << 4) | (s->type & 0xF)));
        bb_write8(&symtab_buf, STV_DEFAULT);
        bb_write16le(&symtab_buf, (uint16_t)(s->defined ? s->shndx : SHN_UNDEF));
    }

    for (int i = 0; i < m->text_relocs.count; i++) {
        const char *rname = m->text_relocs.data[i].sym_name;
        int found = 0;
        for (int j = 0; j < m->syms.count; j++) {
            if (strcmp(m->syms.data[j].name, rname) == 0) { found = 1; break; }
        }
        if (!found) {
            uint32_t no = strtab_add(&strtab, rname);
            bb_write32le(&symtab_buf, no);
            bb_write32le(&symtab_buf, 0);
            bb_write32le(&symtab_buf, 0);
            bb_write8(&symtab_buf, (uint8_t)((STB_GLOBAL << 4) | STT_NOTYPE));
            bb_write8(&symtab_buf, STV_DEFAULT);
            bb_write16le(&symtab_buf, SHN_UNDEF);
            ElfSym us = {0};
            strncpy(us.name, rname, sizeof(us.name) - 1);
            us.bind = STB_GLOBAL;
            us.type = STT_NOTYPE;
            us.defined = 0;
            symarr_push(&m->syms, &us);
        }
    }

    ByteBuf rel_buf;
    bb_init(&rel_buf);
    for (int i = 0; i < m->text_relocs.count; i++) {
        ElfReloc *r = &m->text_relocs.data[i];
        int sym_idx = sym_index32(m, r->sym_name, symtab_info);
        bb_write32le(&rel_buf, (uint32_t)r->offset);
        bb_write32le(&rel_buf, ((uint32_t)sym_idx << 8) | (uint32_t)(r->type & 0xff));
    }

    size_t off = EHDR32_SIZE;
    size_t text_off = off; off += m->text.size;
    off = (off + 3) & ~(size_t)3;
    size_t data_off = off; if (shidx_data >= 0) off += m->data.size;
    off = (off + 3) & ~(size_t)3;
    size_t rodata_off = off; if (shidx_rodata >= 0) off += m->rodata.size;
    off = (off + 3) & ~(size_t)3;
    size_t rel_off = off; if (shidx_rel >= 0) off += rel_buf.size;
    off = (off + 3) & ~(size_t)3;
    size_t symtab_off  = off; off += symtab_buf.size;
    size_t strtab_off  = off; off += strtab.buf.size;
    size_t shstr_off   = off; off += shstrtab.buf.size;
    off = (off + 3) & ~(size_t)3;
    size_t shdr_off    = off;

    /* ELF32 header */
    bb_write8(out, ELF_MAG0); bb_write8(out, ELF_MAG1);
    bb_write8(out, ELF_MAG2); bb_write8(out, ELF_MAG3);
    bb_write8(out, ELFCLASS32);
    bb_write8(out, ELFDATA2LSB);
    bb_write8(out, EV_CURRENT);
    bb_write8(out, ELFOSABI_NONE);
    for (int i = 0; i < 8; i++) bb_write8(out, 0);
    bb_write16le(out, ET_REL);
    bb_write16le(out, EM_386);
    bb_write32le(out, EV_CURRENT);
    bb_write32le(out, 0);                  /* e_entry */
    bb_write32le(out, 0);                  /* e_phoff */
    bb_write32le(out, (uint32_t)shdr_off); /* e_shoff */
    bb_write32le(out, 0);                  /* e_flags */
    bb_write16le(out, EHDR32_SIZE);
    bb_write16le(out, 32);                 /* e_phentsize */
    bb_write16le(out, 0);                  /* e_phnum */
    bb_write16le(out, SHDR32_SIZE);
    bb_write16le(out, (uint16_t)num_sections);
    bb_write16le(out, (uint16_t)shidx_shstr);

    /* Write section data */
    bb_writebytes(out, m->text.data, m->text.size);
    while (out->size < data_off) bb_write8(out, 0);
    if (shidx_data >= 0) bb_writebytes(out, m->data.data, m->data.size);
    while (out->size < rodata_off) bb_write8(out, 0);
    if (shidx_rodata >= 0) bb_writebytes(out, m->rodata.data, m->rodata.size);
    while (out->size < rel_off) bb_write8(out, 0);
    if (shidx_rel >= 0) bb_writebytes(out, rel_buf.data, rel_buf.size);
    while (out->size < symtab_off) bb_write8(out, 0);
    bb_writebytes(out, symtab_buf.data, symtab_buf.size);
    bb_writebytes(out, strtab.buf.data, strtab.buf.size);
    bb_writebytes(out, shstrtab.buf.data, shstrtab.buf.size);
    while (out->size < shdr_off) bb_write8(out, 0);

    elf_write_shdr32(out, sh_null_name, SHT_NULL, 0, 0, 0, 0, 0, 0, 0, 0);
    elf_write_shdr32(out, sh_text_name, SHT_PROGBITS, SHF_ALLOC|SHF_EXECINSTR, 0, (uint32_t)text_off, (uint32_t)m->text.size, 0, 0, 4, 0);
    if (shidx_data >= 0)
        elf_write_shdr32(out, sh_data_name, SHT_PROGBITS, SHF_ALLOC|SHF_WRITE, 0, (uint32_t)data_off, (uint32_t)m->data.size, 0, 0, 4, 0);
    if (shidx_rodata >= 0)
        elf_write_shdr32(out, sh_rodata_name, SHT_PROGBITS, SHF_ALLOC, 0, (uint32_t)rodata_off, (uint32_t)m->rodata.size, 0, 0, 4, 0);
    if (shidx_bss >= 0)
        elf_write_shdr32(out, sh_bss_name, SHT_NOBITS, SHF_ALLOC|SHF_WRITE, 0, 0, (uint32_t)m->bss_size, 0, 0, 4, 0);
    if (shidx_rel >= 0)
        elf_write_shdr32(out, sh_rel_name, SHT_REL, 0, 0, (uint32_t)rel_off, (uint32_t)rel_buf.size, (uint32_t)shidx_symtab, (uint32_t)shidx_text, 4, 8);
    elf_write_shdr32(out, sh_symtab_name, SHT_SYMTAB, 0, 0, (uint32_t)symtab_off, (uint32_t)symtab_buf.size, (uint32_t)shidx_strtab, (uint32_t)symtab_info, 4, SYM32_SIZE);
    elf_write_shdr32(out, sh_strtab_name, SHT_STRTAB, 0, 0, (uint32_t)strtab_off, (uint32_t)strtab.buf.size, 0, 0, 1, 0);
    elf_write_shdr32(out, sh_shstr_name, SHT_STRTAB, 0, 0, (uint32_t)shstr_off, (uint32_t)shstrtab.buf.size, 0, 0, 1, 0);

    bb_free(&symtab_buf);
    bb_free(&rel_buf);
    strtab_free(&strtab);
    strtab_free(&shstrtab);
}

/* =========================================================================
 * Public API
 * ========================================================================= */

ElfObject elf_write_object(const char *asm_text, const char *target,
                           const char *src_path, Arena *arena) {
    int is_x86_64 = (strcmp(target, "x86_64-b1nix") == 0 ||
                     strcmp(target, "x86_64-elf")   == 0 ||
                     strcmp(target, "x86_64-unknown-elf") == 0);
    int is_i386   = (strcmp(target, "i386-b1nix")   == 0 ||
                     strcmp(target, "x86-b1nix")     == 0 ||
                     strcmp(target, "i686-elf")      == 0 ||
                     strcmp(target, "i686-unknown-elf") == 0);

    if (!is_x86_64 && !is_i386) {
        ElfObject empty = {NULL, 0};
        return empty;
    }

    AsmModel m;
    asm_model_init(&m);
    if (is_x86_64) {
        parse_asm_x64(asm_text, src_path, &m);
    } else {
        parse_asm_i386(asm_text, src_path, &m);
    }

    ByteBuf out;
    bb_init(&out);

    if (is_x86_64) {
        write_elf64_object(&m, &out);
    } else {
        write_elf32_object(&m, &out);
    }

    asm_model_free(&m);

    /* Copy into arena */
    uint8_t *result = arena_alloc(arena, out.size);
    memcpy(result, out.data, out.size);
    size_t sz = out.size;
    bb_free(&out);

    ElfObject obj = { result, sz };
    return obj;
}
